INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7453439314706833409/', '𝐒𝐞𝐧𝐢𝐨𝐫 𝐏𝐲𝐭𝐡𝐨𝐧 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 - 𝐁𝐨𝐮𝐭𝐢𝐪𝐮𝐞 𝐇𝐞𝐝𝐠𝐞 𝐅𝐮𝐧𝐝 - 𝐍𝐘𝐂 - 𝐔𝐩 𝐭𝐨 $𝟑𝟓𝟎𝐤 + 𝐓𝐂. We have been retained by a high performing fund that is looking to building out it''s Middle Office Trading Technology team. The role is very close to the business, working directly with stakeholders taking their problems and crafting elegant technical solutions using modern Python. This role would interface with Execution, Portfolio and Order Management systems as well as core systems across the business. If you come from a Hedge Fund or Investment Bank, working across the Middle/Front Office, I would be keen to speak to you! Comp is up to $350k TC + 2 days WFH. For more information, please get in touch! james@durlstonpartners.com …more', '2d • 2 days ago • Visible to anyone on or off LinkedIn', 16, 0, 1, 'image', 1, NULL, 29934);
