INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7453361015750254592/', 'Loads going on at Durlston Partners and we''re looking for the right people to come in and make the most of it. The platform is strong. Warm desks with active mandates, long-standing relationships across the world''s top hedge funds, HFTs, AI labs, fintechs and digital asset firms, and a diverse client base so there''s always something interesting to work on. You come in, take on live accounts, and start billing. Delivery is heavily rewarded with market leading commission - no caps, no thresholds, no desk fees. Zero internal restrictions on access to roles, clients or regions. No partners sitting on house accounts. No gatekeeping. The team is what makes it. Super collaborative across all three offices, with market info, moves, training and search ideas shared in real time. Looking for kind, humble hard-workers at any level, from people 6 months into recruitment to experienced billers wanting a better platform. If you want to come in and bill big on warm desks with a team that genuinely has your back, drop me a message. shannon@durlstonpartners.com …more', '3d • 3 days ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7452272548316131328/', 'Lunchtime meeting yesterday, so took an early 5k to stretch the legs - caught the Horse Guards Parade midway... a reminder of how much I love living in London and working where we do☀️ We''re hiring. Durlston Partners is a specialist talent firm building teams at the frontier of finance and AI. Since 2010, we''ve been trusted by the world''s most demanding investment platforms - leading hedge funds, HFTs, AI research labs, digital asset businesses, fintechs, sovereign wealth funds and tier-1 banks. We''ve built founding quant and engineering teams at firms now managing multi-billion-dollar AUM, placed the founding engineers at spin-outs that became some of the world''s most prominent HFT operations, and been search partners to market-leading hedge funds for over a decade. We offer market-leading commission, equity, bonuses and global incentives, no restrictions on clients or regions, progression genuinely tailored around you. High average fees and consistently outperforming industry billings across the team. If you want a conversation, even informal, drop me a line. hashtag#Hiring hashtag#DurlstonPartners …more', '6d • 6 days ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'video', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7450854278296031233/', 'Great couple of weeks in the London office with Rahnpreet and Joshwa in town - and a big birthday celebration for Joshy while he''s here 🎉 The buzz around the office isn''t just the occasion. Since 2010, Durlston has partnered with the world''s leading AI/ML firms, Hedge Funds, HFTs and Digital Assets players - and the mandates coming through the door right now are some of the strongest we''ve seen. Four offices, one specialist network, and a team raising the bar every week. Client demand is exceptional and we''re hiring across the team. If you want in - let''s talk. hashtag#Hiring hashtag#DurlstonPartners …more', '1w • Edited • 1 week ago • Edited • Visible to anyone on or off LinkedIn', 0, 1, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7447236173758005248/', 'The sun is shining in London and we’re hiring ☀️ If you’re a headhunter either already operating in our space, or currently in recruitment and curious about moving into it, we’re building out the team at Durlston Partners and would love to speak. We’re a specialist search firm focused on quant, tech and data science hiring across hedge funds, HFTs, digital asset firms, fintech and AI companies. It’s a high-performance market where quality, credibility and relationships genuinely matter, and where the work you do has a direct impact on how some of the most sophisticated businesses in the world are built. We’ve spent the last 15+ years building a platform that allows people to operate at a high level - with warm, active mandates across long-standing hedge fund and trading clients, alongside some of the most interesting fintech and AI firms. The model is delivery-focused and genuinely meritocratic, with strong incentives, real autonomy across clients, roles and regions, and no internal barriers to doing good work. We operate globally across London, New York and Dubai, and as a relatively small team, there’s real opportunity to make an impact and shape your own progression - whether that’s staying hands-on, building a team, or developing deeper client relationships. If you’d be open to a conversation, now or in the future, feel free to drop me a message. …more', '2w • 2 weeks ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7445371283015561216/', 'Excited to have Muhammad Aly join our team in Dubai. With 15+ years of specialist recruitment experience across APAC and MENA, and over a decade building networks across the UAE, Mo brings a rare combination of deep market knowledge and genuine commercial instinct to every search. At Durlston Partners, Mo will be focused on placing elite talent across AI, product, and technology with some of the region’s most ambitious organisations, while continuing to build lasting relationships with the most innovative and forward-thinking firms in the market. From AI research labs and innovation teams to high-growth fintechs and global technology consultancies, his focus is on the kind of talent that doesn’t show up on job boards and the kind of relationships that take years to build properly. Outside of work, you’ll usually find him on a padel court, somewhere on a bike, building Lego sets with a level of seriousness that probably warrants its own LinkedIn post, or convinced he’d have made an exceptional chef. Welcome to the team, Mo. Durlston Partners …more', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 50, 4, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7445046538403336192/', 'Why I believe in a strong V Shape bounce for Dubai and Abu Dhabi similar to 2021. The fundamentals haven’t changed in the UAE. At Durlston Partners in Dubai, we have been coming into the office every single day since the conflict began and every single day we have been speaking to our clients; hedge funds, sovereign wealth funds and family offices. We remain 100% committed to Dubai, Abu Dhabi and the whole region. This is the same for at least 80%+ of the people I speak to. The fundamentals haven’t changed: great leadership that serves the people, with intention, with calmness, urgency and vision. The Dubai + Abu Dhabi reserves sit at $2.9 Trillion, that’s 100x the annual budget so the UAE could run the state tax free for 100 years! Dubai will have a whole new image when this is over and will attract even more great people and investment. Just like the US attracted the most positive and hardworking people globally, over 100 years ago, the UAE is now doing the same. Great people build Great nations. Photo: This morning, our team gathered for Breakfast Club at Bisou Restaurant and Founders Dubai …more', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 0, 9, 7, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7444709431365431296/', 'Join our team 💙', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 16, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7444382898683527168/', '2 weeks to go until the Paris Marathon… training has not been enjoyable, but it’s nothing compared to what some of the animals I’m fundraising for have been through, which is a pretty good motivator to keep running. I’m running the Paris Marathon this April to raise money for Elephant Nature Park / Save Elephant Foundation, an organisation I’ve volunteered with multiple times over the years. They rescue abused and captive elephants and give them space to recover in a natural environment, but they also rescue and care for thousands of other animals - dogs from floods and dog meat farms, disabled dogs, cats, buffalo, cows rescued from slaughter and many more. They also run a hospital for elephants, dogs and cats and support animals from outside the park as well. Importantly, they also work with local communities to move away from elephant riding and trekking camps by creating ethical tourism and alternative income sources, which is how long-term change actually happens. If anyone would like to support, donate or share, I would be hugely grateful. All funds will be transferred directly to Save Elephant Foundation after the marathon. Thanks very much for reading. Video: Daniel Frugtniet Hagen making my do intervals last week! https://lnkd.in/euZ9ZpKi …more', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'video', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7442858075373506560/', 'We receive a high volume of messages and applications through the Durlston Partners website and LinkedIn page every day. We really appreciate that a lot of people are looking for new opportunities at the moment, and the team does try to respond and have speculative conversations where possible. That said, many of our clients have very specific requirements, and there are only so many hours in the day, so the team has to prioritise candidates who are most aligned with live roles. If you see a role on our website or LinkedIn that you feel is a good fit, please feel free to send a follow up email to hello@durlstonpartners.com with your CV, a short summary of what you have been doing, and the types of roles and firms you would be interested in. This helps us review your profile properly and keep you in mind for relevant opportunities. Thanks in advance, and we really appreciate your patience. …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 2, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7442484204124303361/', 'Team lunch and golf in Dubai last week to celebrate Joshy’s 5th year at Durlston Partners ⛳ Crazy how fast the time goes. Josh spent four years with our London team, had a brief stint in Ops, and is now out in Dubai absolutely smashing it. We’re continuing to grow across London, Dubai and New York, and we’re always keen to speak with recruiters in our space who might be open to something new. For anyone newer here - Durlston Partners is a specialist tech and trading search firm working across quant, tech, data, AI/ML and digital assets. We partner with hedge funds, trading firms, asset managers and fintechs globally, and have built a collaborative, high-performing platform with warm desks, strong client relationships and real earning potential. If you’re curious about joining us, feel free to drop me a message for a chat. …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7441775530493886465/', 'Had an amazing time in Morzine / Avoriaz last week ⛷️ Only my second time skiing and some of my friends are basically pros, but I managed to keep up (sort of), had far fewer falls than last year, and even made it down a few reds! I avoided skiing for years because everyone else had been going since they were children and I didn’t want to be the one slowing everyone down. Very glad I finally decided to just start anyway. It’s always a bit uncomfortable going into something new where everyone else seems ahead, but it usually pays off. Which probably links quite nicely to careers too. Sometimes the best decisions are the slightly scary ones - moving companies, moving cities, changing markets, trying something you’re not 100% sure you’re ready for yet. If you’re thinking about a new adventure, we’re hiring at Durlston Partners across London, Dubai and New York. Durlston Partners is a specialist tech and trading search firm working across quant, tech, data, AI/ML and digital assets, partnering with hedge funds, trading firms, asset managers and fintechs globally. We’ve built a genuinely collaborative, high-performing platform with warm desks, strong client relationships and plenty of opportunity to grow, bill well and have a good time along the way. If you’re curious about what a move might look like, always happy to have an off-the-record chat. …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7437148402641014784/', 'Pros of working at Durlston Partners: very well fed Cons: growing waistline and more exercise required Managed to squeeze in a 5k lunchtime run today and 10k yesterday as the countdown to the Paris Marathon (one month to go!) continues. Spring is definitely in the air. Life is all about balance though… yesterday’s “refuelling” was a lunchtime feast at Ambassadors Clubhouse (freshly awarded its first Michelin star), today we’ve had CRISP pizza delivered, and Rahnpreet Sandhu also organised a big breakfast order for the team - so I think most of the office is currently in a food coma. All systems go at DP as always, and we’re hiring. For anyone newer here, Durlston Partners is a specialist tech and trading search firm with offices in London, Dubai and New York. We partner with hedge funds, trading firms, asset managers and fintechs globally across quant, tech, AI/ML, data and digital assets, and we’ve built a genuinely collaborative, high-performing platform with warm desks, deep client relationships and unlimited earning potential. If you’re a recruiter in our space and curious about joining, drop me a message. …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7437046115436310529/', '𝗠𝗲𝗲𝘁𝗶𝗻𝗴𝘀 𝗶𝗻 𝗟𝗼𝗻𝗱𝗼𝗻 𝘁𝗼𝗺𝗼𝗿𝗿𝗼𝘄 (𝗧𝘂𝗲𝘀𝗱𝗮𝘆 𝟭𝟬𝘁𝗵) I am in London for a few days and keen to catch up with my network to discuss the market we cover, and how we can help both candidates and hiring teams in London, the Middle East and beyond. - Candidates - happy to give an overview of the global market, cut through the BS with a realistic plan of attack for your next move and answer any other questions you have. - Hiring teams - give an overview of the firms moving in the market, discuss any hiring challenges, and most importantly, advice on the hiring strategy that can work for your needs. - AI Disruption - where is it being implemented well, how can you position yourself for the next few years, and the best opportunities right now. - Launching/new funds - we have assisted multiple funds in building from scratch, all the way from hiring founding team members, to advising on build-out plans and then executing on delivering the best talent. Feel free to reach out if you''re interest - coffee/lunch on me! Rahnpreet Sandhu Durlston Partners …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 1, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7436783887177035778/', 'Had an epic (literally) week of music last week and just feeling very grateful. Mainly coming on here to tell everyone to go and see EPIC: Elvis Presley in Concert because… wow. Honestly wow. Whether you love Elvis, think you hate Elvis, don’t care about Elvis, or know nothing about him - go and see it in the cinema. Somehow managed to get tickets to the Harry Styles one-night-only gig on Fri that was filmed for Netflix - SO good... no phones allowed, only disposable cameras which gave 90s nostalgia (the photos are… not great). And then ABBA Voyage on Saturday, which I’d seen before but is still completely mind-blowing. It genuinely feels like you’re at an ABBA concert. Anyway... an amazing week of music. Slightly random LinkedIn post but sometimes it’s nice to share the things that make life good. Normal work posts resume tomorrow… 🎶 …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7434891469842452481/', 'Lots to celebrate for the DP London team recently. We kicked things off celebrating Daniel’s birthday at CRISP / The Marlborough on Friday, followed by cake in the office yesterday for Jamie, with more celebrations lined up this Friday. A big one coming up too, with Marcus in South Africa for what’s set to be a very special wedding weekend. Plus, we’ve had David join us - already getting stuck in and settling in well. Plenty going on as always. If you’re a firm looking to hire across tech, quant or AI, or a candidate exploring your next move, our team is always happy to help. Email hello@durlstonpartners.com. And if you’re a recruiter in our space looking for the best platform in the market, we’re hiring across London, Dubai and New York. Drop me a message! …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7434511642245378049/', 'Spent last Thursday in a Performance Lab session with Jeremy - was a good opportunity to step back and ask myself if we are doing enough to get the absolute best out of our team. The session focused on leadership energy, accountability and standards - challenging us to be clearer, more intentional and more consistent in how we raise performance without lowering the bar. There are definitely a few things I think we already do well... but as always, there’s plenty of room to improve. I’ve come away with a lot of ideas to implement off the back of it! Thank you, Jeremy :) …more', '1mo • Edited • 1 month ago • Edited • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7434161572467499008/', 'Like most, I''ve been watching events unfold over the weekend, and thoughts are with those directly affected. From London, we’ve been in contact with our team in Dubai, as well as clients and candidates across the UAE. Everyone is safe. While the headlines feel heavy, day-to-day life continues for many. There’s understandably a lot of noise online - we’d encourage our network to rely on verified sources and official guidance rather than unconfirmed clips or AI-generated content. For our clients and candidates: We are here. Processes are continuing. Communication lines remain open. We’re thinking of those more directly impacted and hoping for de-escalation and stability as soon as possible. …more', '1mo • Edited • 1 month ago • Edited • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7432699749117571072/', 'A few of our London team went for Iftar with Siva earlier this week 🌙 Lovely to come together, share food and celebrate something that’s important to one of our own. Wishing everyone in our network observing Ramadan a peaceful and meaningful month. Ramadan Mubarak 🤍 …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7432338344706990080/', 'After what feels like the wettest start to the year I can remember, the sun is finally shining in London ☀️ The office feels brighter this morning, and yesterday’s 7k with Daniel actually felt hot! Run Club will be back soon, so if you’re keen to join us, drop a note to events@durlstonpartners.com. Spring is in the air, and if you’re also thinking about change, we’re hiring globally at DP. Whether you’re: – a recruiter in our space looking to join the best team, – a fintech business planning to grow, or – someone exploring your next move, feel free to drop me a message at shannon@durlstonpartners.com. For anyone newer here, Durlston Partners is a specialist tech and trading search firm with offices in London, Dubai and New York. We work across quant, tech, data, AI/ML and digital assets, partnering with hedge funds, trading firms, asset managers and fintechs globally. We’ve built a high-performing, collaborative platform with warm desks, deep client relationships and genuine earning potential. Sun’s out. Market’s busy. Let’s go. …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7432073271652745216/', 'Could an off-the-record chat be one of the small, good choices you make this year? This is pinned on our office fridge. I must open fridge about 10 times a day (usually when Marcus has hidden office treats from himself in there and I go and find them…), but every now and then I actually notice it. Choosing a new role doesn’t feel like a small choice at the time. It’s a big one. There’s risk, unknowns, trade-offs. I remember when I joined DP, I had a couple of strong offers on the table. DP was the only “unknown” route - I’d worked in the finance space but never in recruitment. It felt like a big leap and (to be honest) slightly too good to be true. Nearly six years later, it’s more than lived up to expectations. Of course it hasn’t all been smooth sailing, there have been challenges and growing pains, but I’m so proud of where the team is today and incredibly grateful for the opportunities I’ve been given. I’m ambitious, hardworking and yes, motivated by earning well. But I also love my life... my friends, family, travelling the world, eating incredible food (arguably some of the best places I’ve ever eaten have been with DP). DP has given me the balance of having a role that stretches and rewards me financially, while still allowing me to actually enjoy life. Somehow I managed 15 countries last year and have already ticked off 3 this year. Recruitment isn’t easy... you have to be good to earn well. But at DP we give people a platform, warm desks, real access and the opportunity to fly. What you do with it is up to you. If you’re not happy where you are, and you’re craving more opportunity, balance, and reward, could an off-the-record chat be one of the small, good choices you make this year? My inbox is open :) …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 4, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7429887133626109952/', '“This is why I love working here - you can post that on LinkedIn!” - Daniel, after Meraj brought in CRISP pizza for a post-lunch snack 🍕 If you asked Daniel to elaborate, I hope he’d say it’s actually our exceptional platform, amazing clients, talented and collaborative team full of good eggs, and a market-leading commission structure that keeps everyone motivated. But yes… the constant stream of very good food deliveries and team lunches probably helps too. (On the flip side, we did have James just walk back in from the gym saying “why, I’m trying SO hard” while clutching the salad he’d just bought, so the yummy food culture is either a perk or a test of willpower depending on your perspective.) We’re hiring. If you’d like to plug into genuinely warm desks, work with brilliant clients, join a collaborative (and fun) team - with the occasional surplus of very good food... drop me a note. …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 4, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7429477723028348929/', 'Also… happy Pancake Day 🥞Managed a quick pancake breakfast with a few of the team this morning. I’d actually booked a table for everyone, but candidate and client calls (plus a lingering New Year health kick…) had other plans. The sun is finally shining in London, the market is super busy, and there’s lots of exciting stuff going on at DP. We’re always on the hunt for experienced recruiters in our space. If you work across tech, quant, AI/ML, digital assets or trading and are looking for a strong platform to plug into, we can offer exactly that. We heavily incentivise delivery, there are no restrictions on access to roles or clients, and you’ll get direct exposure to incredible accounts from day one. Durlston Partners is a specialist tech and trading search firm with offices in London, Dubai and New York. We partner with hedge funds, trading firms, asset managers and fintechs globally, and have built a collaborative, high-performing team with warm desks and deep client relationships. If you’re curious, drop me a message. …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7429466885542490112/', 'Happy Lunar New Year from all of us at Durlston Partners 🧧 Wishing our clients, candidates, colleagues and friends who are celebrating a year filled with health, happiness and prosperity. As we welcome the Year of the Horse, we’re looking forward to a year of energy, momentum and continued growth across all of our global offices. 新年快乐 - Gong Xi Fa Cai! …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7427631518027579392/', '8 weeks to go until the Paris Marathon… help 😅 It got very real this weekend with a 24km run, and I’ve got long runs planned every weekend from now until race day. This April, I’m running 26.2 miles for Elephant Nature Park / Save Elephant Foundation - an organisation I’ve volunteered with three times since 2018. ENP rescues sick and abused captive elephants and gives them space to heal in a natural environment. They also work directly with local communities to end elephant trekking and riding by creating ethical, sustainable alternatives. What many people don’t realise is that a huge number of so-called “sanctuaries” still exploit elephants. ENP is one of the very few that puts animal welfare above tourism. At their main park they care not only for rescued elephants, but also: 750 dogs saved from floods, dog meat farms and the streets (including 70+ disabled dogs given a second chance), 2,000+ cats, buffalo, cows rescued from slaughter, birds - and almost any animal they can help They have just built a hospital treating elephants, dogs and cats, including animals from outside the park too! The heartbreaking truth is that almost every working elephant has endured “The Crush” (Pajan) - a brutal process designed to break their spirit through isolation, starvation and beatings. When you see a “calm” elephant giving rides or performing, it isn’t obedience, it’s fear. If you’d like to support, donate or share, I’d be hugely grateful. As ENP is based in Thailand and not supported on UK fundraising platforms, I’m collecting via GoFundMe and will withdraw and transfer the funds directly to Save Elephant Foundation after the marathon. Thank you for reading 🤍 https://lnkd.in/e4fZQ5Yz …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 1, 2, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7427385788373434368/', 'A little snapshot of the London team in Dubai at the start of the month ☀️ A very welcome change from what has felt like the wettest start to the year ever in London! We’re hiring across London, Dubai and New York. For anyone new here, Durlston Partners is a specialist tech and trading search firm working across quant, tech, data, AI/ML and digital assets. We partner with hedge funds, prop trading firms, asset managers and fintechs globally, and have built a genuinely collaborative, high-performing platform with warm desks and deep client relationships. If you’re a recruiter in our space and curious about what a stronger platform could look like, or you’ve ever considered a move to Dubai (we can support relocation), I’d love to have a chat. Great, collaborative team, plenty of opportunity to come in and hit the ground running and bill (earn) big from day one. …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 1, 3, 'video', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7424740460126097409/', 'These flowers are sitting on my desk today! They’re from a candidate I helped relocate to the UAE, who started their new role this Monday. Totally unexpected, but very appreciated! Moments like this are a reminder that recruitment isn’t just about opportunities. It’s about people trusting you with a big life move. Grateful to be part of that journey! That’s also why I’m starting February working on genuinely exciting Data Scientist roles in Abu Dhabi! £120k–£300k total compensation, with relocation supported. These opportunities aren’t just about the job. They’re about lifestyle, long-term growth, and making a meaningful professional move. You’ll be helping build a centralised data science function within a quantitative investment platform. Much of the work is greenfield, highly exploratory, and genuinely interesting from a research and engineering perspective. Backgrounds are intentionally broad. We hire from big tech, alternative data, research-heavy environments, and non-finance roles where the skillset maps well. Academic rigour is valued here, particularly from research-focused universities. If Abu Dhabi has ever been on your radar, this might finally be the right time. If this sounds like you, send a CV and a brief note to dana@durlstonpartners.com or message me directly. …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 8, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7424457492941832192/', 'Lovely few days with the team in Dubai with the whole London team - the winter sunshine was very much appreciated! We’re in the process of making an offer to a great Operations Associate in Dubai, and we’ve also had some brilliant conversations with people across the region. We’re continuing to grow across London, Dubai and New York, and we’re hiring in all three locations. For anyone who doesn’t know us, Durlston Partners is a specialist tech and trading search firm working across quant, tech, data, AI/ML and digital assets. We partner with some of the most sophisticated hedge funds, trading firms, asset managers and fintechs globally, and have built a genuinely collaborative, high-performing team with warm desks, deep client relationships and a long-term mindset. We work hard, support each other properly, invest in our people, and create platforms where individuals can plug in and make an impact from day one. If you’re a recruiter thinking about your next move, a candidate curious about the market, or a client looking to scale this year, I’d love to chat. shannon@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7423264366684278784/', '19.15km ✔️ Double Palm run ✔️ Thank god for Daniel Frugtniet Hagen meeting me at 11km with fuel and water and constant pep talks through the last 8k. Beautiful run, beautiful day, and a bit of a sunbathe before polo with the crew ☀️ Not the easiest one after a yacht day yesterday… but we got it done. I’m running the Paris Marathon for Elephant Nature Park - an incredible charity doing life-changing work for rescued elephants and other animals. If you’re able to sponsor (even a small amount), I’d be hugely grateful 🐘💛 https://lnkd.in/eDh-MKv9 …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 1, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7422886644174712832/', 'Post Friday morning run views ☀️ The whole London team are out in Dubai this week spending some proper time together, which has been great… but marathon training doesn’t pause. Paris will be here before I know it, so I’m thinking I might brave an early-morning half while I’m out here. 👀 If anyone in Dubai has a favourite running route, please send it my way. Back in London on Monday and we are hiring Recruitment Consultants across London, Dubai and New York. If you’re already billing and want to step into warm desks, great clients, and a genuinely collaborative and fun environment, Durlston Partners could be a great move! Drop me a message or email shannon@durlstonpartners.com if you’d like a confidential chat. …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7421962781538734081/', 'Join our team :)', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 22, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7421844080747343873/', 'We’ve had a slightly overwhelming response to our Operations Associate role in Dubai - blown away by the quality of candidates. Thank you so much to everyone who’s applied. I’m working through applications and shortlisting now, so please bear with me while I try to get back to everyone 🙏 Separately, we’re also hiring experienced Recruitment Consultants across London, Dubai and New York. If you’ve got experience in our space and are looking to step into warm desks with active, engaged accounts, real ownership, and the chance to build something properly, all within a highly collaborative, no-noise team, we’d love to hear from you. Compensation is strong and aligned with performance, and you’ll be backed by solid ops, data and infrastructure from day one. If that sounds like you (or someone you know), feel free to get in touch or drop a CV to shannon@durlstonpartners.com. …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 1, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7421476243612655616/', 'This April, I’m running the Paris Marathon to raise funds for Elephant Nature Park / Save Elephant Foundation 🐘 https://lnkd.in/gext5ZPZ I ran my first half marathon around London this weekend and it was… a shock to the system 😅 but it’s lit the fire to train hard and put those miles towards something that matters. Elephant Nature Park rescues elephants who’ve suffered unimaginable cruelty and works to end elephant riding and trekking by supporting ethical, community-led alternatives. They also care for hundreds of rescued dogs, cats, and other animals - and are about to run a hospital treating animals in need across the region. Most working elephants have endured “The Crush” - a brutal process designed to break their spirit. ENP exists to stop that cycle, every single day. If you’re able to donate, share, or learn more, it genuinely makes a difference. Thank you 🤍 …more', '3mo • Edited • 3 months ago • Edited • Visible to anyone on or off LinkedIn', 0, 0, 1, 'article', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7420021281321959424/', 'Join our team :)', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 29, 4, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7419391120868302849/', 'As our Dubai office continues to grow, we’re looking for an exceptional Office Manager / Team Coordinator to become the lynchpin of the team on the ground. This is a support role at its core, but with huge scope to grow, take ownership, and help shape what we’re building in the region. This person will sit at the heart of the Dubai office, working closely with me (based in London) and alongside our teams in London, Dubai and New York. You’ll be the go-to for keeping things running smoothly day to day, freeing up the team to focus on clients, candidates and growth, while also getting exposure to recruitment, operations, marketing, events and more! Dubai is a key growth hub for us. The office is scaling quickly, client demand is strong, and there’s real opportunity here for someone who’s organised, proactive, switched on, and excited by being part of something that’s still being built - a trusted right-hand, organiser, problem-solver! If you love being in the thick of it, enjoy bringing structure to fast-moving environments, and want a role where you’ll learn a huge amount and grow with the business, I’d love to hear from you. Drop me a message for a confidential chat. …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 4, 3, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7418923106838278144/', 'Back in action after an amazing three weeks in Malaysia and Thailand, with the final week volunteering at Elephant Nature Park (more on that soon, because it was very special). For now, it’s straight back into it. The team are all systems go for 2026 and there’s a huge amount of exciting stuff already in motion across London, New York and Dubai. We’re looking to grow our team in London and Dubai this year, so if you’re interested even in a tentative chat, my door is open! We work with some of the most exciting hedge funds, trading firms, AI/ML labs and fintechs in the world, and we’ve created an environment where great recruiters can do their best work - warm desks, deep client relationships, genuinely collaborative culture, big fees, and a commission structure that properly rewards performance. shannon@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 2, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7417528832573874178/', 'We''re growing and hiring across our London and Dubai offices. One of the main reasons people join us and what surprises them most during interviews is the level of trust and respect we have for each other. We don''t operate in a cutthroat way. We hear horror stories during interviews about practices at other competitors. Someone who recently joined us shared that at their previous firm, just two months after they''d placed a candidate at a market maker, their colleague secretly contacted that same candidate trying to poach them for another placement to collect a fee. This kind of behaviour makes you look incompetent and it damages your reputation for short-sighted gain. But you can’t be blamed if you’re incentivised to do this. If your firm incentivises you to undercut your colleagues like this, they don''t care about you or the quality of service you provide. By comparison, a few years ago I saw an SRE on our system that Marcus Osborne had previously worked with and met for coffee. This was one of those "attach the invoice" to the intro candidates. The candidate hadn''t been contacted in three months. According to our ownership rules, relationships expire after two months, so technically this candidate was fair game and I could have taken over with no issues. Instead, I gave Marcus a heads up (as painful as that was) and sure enough, he placed the candidate a few weeks later for a sizable fee. Why do we operate this way? The favors get repaid. It reduces friction and tension within the team. People stay with the company longer. It''s how we build something sustainable! Screenshot attached of that painful but rewarding exchange with Marcus …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 4, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7417374686222651393/', 'Hope everyone’s had a great start to 2026. I’m spending the final week of my travels volunteering at Elephant Nature Park, a place very close to my heart. They rescue and rehabilitate sick and injured elephants from trekking, logging and circus environments, work closely with local communities on education, and help liberate elephants through saddle-off projects. It’s an incredibly special place, a very wholesome way to reset before heading back into the year. Feeling refreshed, grateful, and ready to throw myself back into work next week - followed shortly by a trip to Dubai with the London team to celebrate a strong 2025 and kick off what’s shaping up to be an exciting year ahead :) If anyone is interested to hear more about ENP, I wrote a blog on my 2018/19 experiences here: https://lnkd.in/gH7BfpVY …more', '3mo • Edited • 3 months ago • Edited • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7415355992294785024/', 'I’ll be back in the office on 20th Jan and keen to line up some conversations! Drop me a message :)', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7413890840936222720/', 'The Durlston Partners Dubai Team enjoyed an incentive trip to Goa at the end of last year before heading into a very productive December. Our deals channel was still active through the extended Christmas break, something which still gets me going, even after a decade of doing this job. We''re heading into 2026 with a new office in Dubai and space for some more recruiters. We don''t rush into hiring and have a pretty brutal fail rate but that doesn''t mean you don''t stand a chance with us. The easiest way of figuring out if we''re for you, will likely be by asking yourself; "do I love recruitment but hate my current workplace?" If you want to join a team of "good eggs", then please get in touch. I wear my heart on my sleeve, so you can expect an honest break-down of what it''ll be like to work with us. warwick@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 1, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7412047895694057472/', 'Happy New Year’s Eve from sunny Langkawi 🌴 I’ve just come off an incredible couple of weeks with my dad island-hopping around the Caribbean, followed by Christmas with the family. Have landed in Malaysia, en route to Thailand to explore and end with a return visit to Elephant Nature Park, a place very close to my heart and somewhere I’ve volunteered at lots before. While I’ve been away, the DP teams in London, New York and Dubai have also (mostly!) powered down, but with 2026 firmly in their sights. We finished 2025 exceptionally strong: some brilliant hires, some whopper placements, packed-out hedge fund and industry events across London and Dubai, multiple Women at the Table events, and continued momentum across all regions. Super proud of this team ☺️ On a personal note, 2025 has been a pretty special year too! Here’s to a happy, healthy and exciting 2026! Be kind to yourself, each other and the 🌎 …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 43, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7404810427395756032/', 'Last day in the Durlston Partners office before I disappear for a mini sabbatical ✈️ Was in early (partly excitement, partly the mountain of work I need to do before we head to Winter Wonderland at lunch…) and caught a gorgeous sunrise over Regent Street. Something special about walking these streets before the madness starts . We’ve had a brilliant year across London, Dubai and New York and 2026 is already shaping up to be as good, maybe better! I’ll be trying to switch off properly while I’m away, so if you’re: • a candidate exploring new roles, • a business looking to grow, or • a tech/quant recruiter keen to join the best team in London / Dubai / NY… please drop a note to ops@durlstonpartners.com and someone will be in touch. I’ll pick up anything non-urgent when I’m back! Have a wonderful Christmas and New Year - be kind to yourself, each other, and the world. 💙🎄✨ …more', '4mo • Edited • 4 months ago • Edited • Visible to anyone on or off LinkedIn', 30, 3, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7403795539387125760/', 'Amazing time at the Durlston Partners London Christmas dinner🎄✨ We usually try to bring the whole team from Dubai and New York together in London, but with everyone’s travel plans - especially since we give the entire company two bonus weeks off over Christmas and New Year - it’s increasingly difficult to get all of us in the same room at once at this time of year. We still had our usual end-of-year round-up and awards: a reminder of just how much we’ve achieved as a team this year. London then headed off to Shanghai Me for the most incredible feast with the best views in the house. I’m about to head off myself for a mini sabbatical over Christmas and New Year - some travelling and sunshine (hopefully!), and I won’t be back until mid-January. I’ve got a few days left in the office and would love to speak to exceptional recruiters who might want to join us in 2026. We’re a specialist tech & trading search firm working with hedge funds, HFTs, AI/ML firms, prop shops, fintechs and digital asset firms across London, Dubai & New York. Warm desks, deep client relationships, no commission thresholds, no desk fees, no caps - meaning you can plug straight into our platform and bill from day one. 2026 is already shaping up to be fab, and we’re excited to bring a few more great people into the journey. If you’d like to chat before I disappear, drop me a message. If you want to speak with one of the team while I’m away, email ops@durlstonpartners.com and they’ll look after you. Here’s to a big finish to 2025 and an even bigger 2026 ✨ …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 39, 2, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7403725534473641984/', 'We were delighted to partner with BlueCove for this fantastic Women at the Table event earlier this month. A huge thank you to Diana, Rhea and Rachel for such insightful technical talks, and to the whole BlueCove team for being brilliant collaborators throughout. It was a pleasure to bring together so many inspiring finance and technology professionals - and we’re looking forward to hosting more events like this in 2026. https://lnkd.in/eGzWqwvZ …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 8, 1, 1, 'article', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7402369747054637057/', 'Incredibly proud to see Durlston Partners collaborated with BlueCove! Fantastic event and amazing speakers sharing their insights. A huge thank you to the BlueCove''s team for being such wonderful partners. And a special shoutout to our own Shannon Palmer, the driving force behind this incredible series. Can''t wait to see the next one! https://lnkd.in/diRuwv8e …more', '4mo • Edited • 4 months ago • Edited • Visible to anyone on or off LinkedIn', 14, 0, 1, 'article', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7401545745356464128/', 'The UAE hedge fund ecosystem is scaling and our 100 Hedge Funds event in Dubai proved it. The region isn’t just growing - it’s becoming a global hub. It’s been a privilege for us at Durlston Partners to sit in the middle of this evolution over the last few years, helping build teams across Dubai and Abu Dhabi. We’ve shared the recap, photos, and video here: https://lnkd.in/enCX2-ya Next up: • 100 Hedge Funds Abu Dhabi • 100 Hedge Funds Dubai • Women at the Table London • 100 Hedge Funds London • 100 AI Firms London If you’d like to attend or partner with us for any of the above, email events@durlstonpartners.com. PS, if you''re interested in a move or if you''re hiring in the region, reach our to our Dubai dream team: Rahnpreet Sandhu Joshwa Shah Vax Bahram Dana Bahram Jared Wolfaardt James Skelt Warwick Poelman (واريك بولمان) …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 12, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7401177718475739137/', '❤️', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7400186095700692992/', 'It’s officially Christmas at Durlston Partners 🎄✨ We’re on the three-week countdown to our annual two-week bonus holiday, but the market clearly didn’t get the memo… it is busier than ever! Interviews are flying in, offers are going out, and we’ve even had starters confirmed before year-end - no signs of slowing down at all. If you’re a candidate exploring your next move, our team has a huge amount live right now. Drop your CV to hello@durlstonpartners.com and one of us will be in touch if we have something relevant for your profile. If you’re a client looking to make the most of December and get ahead of the January hiring rush, we’d love to support you. And if you’re a recruiter in our space… we’re hiring for January starts - next year is set to be a big one. Warm desks, brilliant clients, no restrictions on access to roles or clients, no thresholds, no desk fees, and the ability to plug into our platform and bill from day one. Plus proper incentives and rewards for performance. Exciting end to the year strong and even bigger things ahead. 🎄🚀 …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 10, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7399786075705167873/', 'Happy Thanksgiving to our US colleagues, clients, and candidates! 🦃🤍 Wishing you all a wonderful day with friends, family, good food, and (hopefully) a proper switch-off. …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 11, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7399398723320967168/', 'Not every day you see tractors rolling down Regent Street… but here we are - Budget Day in the UK 🇬🇧🚜 Depending on the outcome today, plenty of firms will be reassessing their hiring plans, expansion strategy, or even where they want to base teams. The good news for candidates is that we’re working on roles globally, so whether you''re looking to stay put, relocate, or explore international options, our team has you covered. We partner with hedge funds, HFTs, prop shops, fintechs and AI/ML firms on roles across quant, engineering, trading, research, data, and digital assets. Momentum is strong heading into year-end, and 2026 is already shaping up to be a big hiring year. And if you''re a recruiter thinking about a move yourself, we’re hiring in London and Dubai and always keen to speak with talented people in our space. If you’re hiring, looking for your next role, or considering a relocation, drop me a message! …more', '5mo • Edited • 5 months ago • Edited • Visible to anyone on or off LinkedIn', 16, 0, 0, 'video', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7398997630019715072/', 'This month we hosted our latest Women at the Table event in partnership with BlueCove - and what an inspiring evening it was. Women across the tech and trading space joined us for an evening of conversation, connection, and insight. BlueCove - founded in 2018 as a scientific asset management firm bringing together leading investment and engineering professionals to research, develop and deploy state-of-the-art scientific investment processes in fixed income - kindly opened their doors and provided the perfect setting for the night. We were incredibly fortunate to hear from three exceptional speakers from BlueCove: Rhea Potdar, Diana Fomina, CFA & Rachel Brown. Events like this are exactly why Women at the Table exists - to create spaces where women across the investment and technology landscape can meet peers, learn from leaders, and feel seen, supported and celebrated. A huge thank you to the BlueCove team for partnering with us and to everyone who joined us! If you’d like to attend, collaborate, or get involved in the next event, drop us a note at events@durlstonpartners.com. & don''t forget to join our community: https://lnkd.in/e8EXxtFm …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 21, 0, 1, 'video', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7398635249842429953/', 'Still buzzing from our 100 Hedge Funds event in Dubai! A big thank you to IG Prime, HAS Law Firm, and Paragon Consulting Partners for partnering with us! We’re already looking ahead to 2025 with events across: • Abu Dhabi • Dubai • London • New York If you’d like to be involved - attending, speaking, sponsoring, or collaborating - drop us a note at events@durlstonpartners.com. Dubai set the bar very high… can’t wait to see what next year brings. …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 25, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7396864378836393984/', 'Big thanks to everyone who joined us at our 100 Hedge Funds event in Dubai recently! The room was packed with good folks from hedge funds, sovereign wealth funds, family offices, HFT, AI, and digital assets. We call came together to celebrate the city''s emergence as a home for the future of buy-side finance. Especially great to see a couple of software engineer friends from my beloved hometown Aylesbury in the mix. Thank you to all our sponsors, see you at the next one! IG Prime, HAS Law Firm, Paragon Consulting Partners, Zofeur, Quant Fin Ltd, PANIO, Founders Dubai Upcoming events in 2026: • 100 Hedge Funds – Abu Dhabi (February) • 100 Hedge Funds – Dubai (March) • Women at the Table – London (TBC) • 100 Hedge Funds – London (April) • 100 AI Firms – London (May) hashtag#DPDMCC Durlston Partners …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 17, 0, 1, 'video', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7396494904908218369/', 'A huge thank you to everyone who joined us at our 100 Hedge Funds event in Dubai earlier this month. The room was packed with brilliant people across hedge funds, trading, fintech, and digital assets, and the energy reflected the momentum building in the region. We’re excited to keep building spaces where this community can connect, collaborate, and share ideas. If you’d like to get involved - whether attending, partnering, or contributing - we’d love to hear from you. Upcoming events: • 100 Hedge Funds – Abu Dhabi (February) • 100 Hedge Funds – Dubai (March) • Women at the Table – London (TBC) • 100 Hedge Funds – London (April) • 100 AI Firms – London (May) To attend, sponsor, or get involved: events@durlstonpartners.com. You can see more photos here: https://lnkd.in/enCX2-ya …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 28, 2, 2, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7396139978147127296/', 'Happy sunny Monday from London! ☀️We’re somehow already hurtling towards the end of the year, and things are only getting busier across all of our markets. If you’re a candidate thinking about a move in the new year, or you work for a firm planning to build out teams in 2026, we’d love to speak with you. Durlston Partners partners with leading hedge funds, HFTs, prop shops, fintechs and AI/ML firms globally, hiring across quant, technology, data, trading, and digital assets. With deep relationships and strong delivery teams in London, Dubai and New York, we’re well placed to support whatever you’re planning next. We’re also hiring internally for January in both London and Dubai, so if you’re a recruiter looking for a high-performing, supportive team and a platform where you can genuinely bill big from day one, drop me a message. Here’s to a strong finish to 2025 and an even bigger 2026! 🚀 …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 15, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7396118386822316032/', 'Durlston Partners 100 Hedge Funds Event - Dubai 🇦🇪 What an evening! This month we hosted our 100 Hedge Funds event at Sexy Fish DIFC, and it was absolutely incredible - a massively oversubscribed night bringing together some of the most brilliant minds in the region. The energy in the room was electric and a real reflection of the momentum and appetite for growth in the UAE. It’s an exciting time to be here, and we’re proud to be part of building this community. Huge thank you to our amazing partners - IG Prime, HAS Law Firm, and Paragon Consulting Partners! We’re already planning future events across London, Dubai, Abu Dhabi, and New York, so if you’d like to attend, sponsor, or get involved, drop us a message or email events@durlstonpartners.com and we’ll keep you posted. …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 16, 0, 2, 'video', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7395018603005153281/', 'Durlston Partners 100 Hedge Funds Event - Dubai 🇦🇪 What an evening! Last week we hosted our 100 Hedge Funds event at Sexy Fish DIFC, and it was absolutely incredible - a massively oversubscribed night bringing together some of the most brilliant minds in the region. The energy in the room was electric and a real reflection of the momentum and appetite for growth in the UAE. It’s an exciting time to be here, and we’re proud to be part of building this community. Huge thank you to our amazing partners - IG Prime, HAS Law Firm, and Paragon Consulting Partners! We’re already planning future events across London, Dubai, Abu Dhabi, and New York, so if you’d like to attend, sponsor, or get involved, drop us a message or email events@durlstonpartners.com and we’ll keep you posted. …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 40, 1, 3, 'video', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7390058823660617728/', 'Lovely afternoon with the team so thought I’d share before signing off for Friday (and packing to head out to Dubai for our 100 Hedge Funds event next Thursday 🌴). It’s been a brilliant week - lots going on, some exciting wins, and we celebrated two big DP anniversaries (6 years and 4 years!) over a great lunch. Sad to leave the London crew for a bit but very excited to see the Dubai team next week - perfectly timed for sunshine! Recruiters in Dubai: I’ll be around all week and have time to meet great people in the space. If you''re exploring your next move or curious about Durlston Partners, would love to grab a coffee. At Durlston Partners, we partner with the world’s leading hedge funds, HFTs, AI labs, crypto firms, and fintechs - hiring across tech, quant, data, AI/ML and digital assets. We offer warm desks and deep client relationships (start billing big from day one), market-leading commission up, additional BD incentives, equity & profit-share, global offices: London | Dubai | New York, high-performing but genuinely collaborative culture, 2-week Christmas bonus break, top private healthcare, and regular socials & incentives! If you''re in Dubai next week and keen to chat, or you''re London-based and planning a move, drop me a message. Always happy to have a confidential conversation. Have a great weekend everyone ✨ …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7389592592625188864/', 'Been awesome having Matthew Leon spend time with both our Dubai and London teams over the last couple of weeks! I’m about to escape the dark nights myself and head to Dubai next week for our 100 Hedge Funds event and to hang out with our Dubai team too. Perfect timing - November sunshine is exactly what I need ☀️ We’re still looking to bring on exceptional people. At Durlston Partners, we partner with some of the most exciting hedge funds, HFTs, trading firms and high-growth fintechs globally - working across tech, quant, AI/ML and digital assets. Our desks are warm, our relationships deep, and we give people the platform to bill big and grow fast. If you’re a recruiter in the space and want to work with the best team, drop me a message for a confidential chat. Excited for a big end to the year 🚀 …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 0, 2, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7389212089782857729/', 'Busy last few hours in Singapore. Catching up with friends old and new at the Transport Logistics expo. Hurricane Modular Commerce Ltd Martyn Noble Jordie Geuyen Tony Lugg TCE Digital Transformation Champion Rod Talbot …more', '5mo • Edited • 5 months ago • Edited • Visible to anyone on or off LinkedIn', 17, 3, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7388537643627618304/', 'Just two weeks to go until our next Women at the Table event in partnership with BlueCove. We’re excited to announce our next speaker, Rachel Brown. Rachel is an Engineer in BlueCove’s Quant Engineering team, where she plays a central role in shaping the firm’s data strategy. She has designed and implemented BlueCove’s Extract, Transform, and Load (ETL) pipeline for the firm’s Data Warehouse and works closely with teams across the business to unify data services that underpin investment and research processes. Before joining BlueCove in 2025, Rachel led the data function at Fulcrum Asset Management, overseeing a major transformation of the firm’s data ingestion, validation, and delivery pipelines. Prior to this, she worked as a data science consultant within HSBC’s Capital Finance and Investment Bank, and she began her career with an internship at Coutts & Co, a UK-based private bank. Rachel holds an MEng in Engineering from Imperial College London. We’re looking forward to hearing from Rachel and the other incredible women at BlueCove as they share their experiences and insights on the night. 📅 Date & Time: Tuesday 11th November, from 6pm 📍 Location: Mayfair, London …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 16, 1, 2, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7388445355358519296/', 'Trade Under Pressure: Navigating Tariff Shifts and Customs and the Complexity Across APAC presented at the TAPA Transported Asset Protection Association Conference in Sentosa hashtag#Singapore. * How rising tariffs and trade realignments are reshaping regional supply chains and market access under RCEP and CPTPP. * Explore how export controls, dual-use goods regulations, and ESG-linked customs checks are tightening across APAC. * Understand how diverging national policies and tariff treatments are challenging regional integration and increasing compliance risks. Great presentation from Martin Palmer -Founder and Board Member Hurricane Modular Commerce Ltd former Head of Customs at TNT Express Worldwide …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 26, 1, 4, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7387449025613942785/', 'We’re getting close! Our 100 Hedge Funds Event is coming up in just a couple of weeks, 6th November in Dubai (DIFC), and we’ve had an epic response so far. The hedge fund scene in the UAE has exploded in recent years, now home to 150+ funds across Dubai and Abu Dhabi, and we’ve been fortunate to help build many of them. This event will bring together leaders from across the industry for an evening of conversation, connection, and celebration of the region’s rapid growth. There are still a few spots left - if you’d like to attend or find out more, drop us a line at events@durlstonpartners.com. …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 9, 1, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7387039576646787072/', 'We’re getting close! Our 100 Hedge Funds Event is coming up in just a couple of weeks, 6th November in Dubai (DIFC), and we’ve had an epic response so far. The hedge fund scene in the UAE has exploded in recent years, now home to 150+ funds across Dubai and Abu Dhabi, and we’ve been fortunate to help build many of them. This event will bring together leaders from across the industry for an evening of conversation, connection, and celebration of the region’s rapid growth. There are still a few spots left - if you’d like to attend or find out more, drop us a line at events@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 15, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7386304811723546625/', 'You know Christmas is coming when the Regent Street angels go up ✨ (photo right outside of our office). Ready for the chaos of Christmas over the next few months… with the dark nights setting in early, the lights make the city feel a bit more magical. As ever, feeling lucky to work on one of the most iconic streets in London. The team are pushing for a super strong end to the year with plenty lined up for 2026 before switching off properly during the two weeks of bonus Christmas leave everyone gets. I’m taking a slightly longer break myself over Christmas, but between now and then I’m keen to speak with experienced recruiters in our space. We’ve got a ton of exciting stuff happening across London, Dubai, and New York - and a platform you can plug straight into and start billing big right away. At Durlston Partners, we’re a leading tech and trading search firm partnering with some of the world’s top hedge funds, HFTs, fintechs, prop shops, and asset managers, hiring across quant, tech, data, AI/ML, and digital assets. We offer market-leading commission, no thresholds, caps, or desk fees, plus cash bonuses, profit share, and equity opportunity. Desks are genuinely warm, relationships are deep, and our average fee per placement is high, with plenty of deals way north of six figures. All the usual good stuff in terms of benefits: two-week Christmas bonus break, health insurance, wellness allowance, team lunches, and global incentives - it’s a strong setup for ambitious recruiters. Even if you’re not actively looking, always happy to have an informal chat. There’s also the option to relocate to Dubai if sunshine and tax-free commission sound tempting ☀️ hashtag#DurlstonPartners hashtag#Hiring hashtag#Tech hashtag#Quant hashtag#AI hashtag#Recruitment hashtag#Finance hashtag#TeamDP hashtag#London hashtag#Dubai hashtag#NewYork …more', '6mo • Edited • 6 months ago • Edited • Visible to anyone on or off LinkedIn', 11, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7386051625427320833/', 'Your next career move might be below 👇 I’m always looking to connect with talented professionals across Software Engineering, Infrastructure, Quant Research, ML, etc. That said, here are some of the most exciting and fast-moving opportunities I’m currently working on: 🖥️ CRYPTO 🖥️ 🟢 Site Reliability Engineer (Linux) - Crypto HFT - Fully Remote, US hours - $450k TC - (HFT/Trading background required) 🟢 Platform Engineer - Crypto HFT - London (Hybrid) - £85k + bonuses 🟢 DevOps Engineer - Crypto Trading firm - Fully Remote (Worldwide) - $120k + bonuses 🤖 AI 🤖 🟡 Founding DevOps Engineer - AI Tech firm - NYC/San Francisco - $350k + equity 🟡 Software Engineers - AI Tech firm – NYC/San Francisco - $500k + equity 🟡 Machine Learning Engineer - AI Start-Up - London - £250k - (Looking for PhDs with ML experience) 📈 TRADING 📈 🔵 DevOps Engineer - Quant Trading - Mumbai - $80k 🔵 C++ Software Developers - Quant Trading - Dubai 🔵 C++ Software Developers - HFT – Mumbai 🔵 Python/C++ Software Developers (Trading/Quant backgrounds) - London, Amsterdam, UAE, Remote - Various positions If you’re open to new opportunities or simply curious about what’s out there, let’s have a chat! 💬 Drop me a message or email me at david@durlstonpartners.com 💬 …more', '6mo • Edited • 6 months ago • Edited • Visible to anyone on or off LinkedIn', 13, 1, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7384490580325715968/', 'We’re excited for our upcoming 100 Hedge Funds Event in Dubai (DIFC) on 6th November! The hedge fund scene in the UAE has exploded - now home to over 150 funds across Dubai and Abu Dhabi - and we’ve been fortunate to help build many of them. This event will bring together leaders from across the industry for an evening of conversation, connection, and celebration of the region’s rapid growth. If you’d like to find out more or request an invite, please reach out to events@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 6, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7384339296436256768/', 'We’re a few weeks away from Durlston Partners’ inaugural hedge fund event in Dubai, open to those working on the buyside, sellside and crypto. As a fun bit of history, we’ve been hosting these events since before I joined in 2017, known back then as the “Hedge Fund Gathering”. We’re bringing the same ingredients to the UAE; great people + tasty food + excellent location. Please message me directly to confirm your attendance, I’d love to welcome as many of you as possible. 📩 warwick@durlstonpartners.com 📲 TG @cryptowarwick …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 12, 0, 1, 'image', 1, NULL, 29934);
