INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7383973616910049280/', '✨ We’re super excited for our next Women at the Table event — this time in partnership with the brilliant team at BlueCove. Our first speaker will be Rhea Potdar 👇 Rhea is Head of Systems Engineering at BlueCove where she leads a team of Engineers focussed on deliveries to scale the firm across various business lines and building the systems through which BlueCove’s firmwide investment process runs. Prior to joining the firm in 2019, Rhea worked as a Software Engineer at Goldman Sachs from 2013 - 2019 in Controllers Technology and Investment Banking Technology, latterly as Vice President of Debt Capital Markets Technology. Rhea received her Masters of Engineering in Computer Science from Imperial College London in 2013. Can’t wait to hear from her! This evening will be a fantastic opportunity to reconnect with others in the space, meet new faces, and hear directly from some of the talented women in BlueCove’s Engineering and Quant Research teams as they share their technical insights and career journeys. 💡 About BlueCove: Founded in 2018, BlueCove is a scientific asset management firm bringing together leading investment and engineering professionals to research, develop and deploy state-of-the-art scientific investment processes in fixed income management. 📅 Date & Time: Tuesday 11th November, from 6pm 📍 Location: Mayfair, London We have a few spots left - email events@durlstonpartners.com ASAP to register your interest. …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 6, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7383502434767364096/', '✨ We’re super excited for our next Women at the Table event - this time in partnership with the brilliant team at BlueCove. Our first speaker will be Rhea Potdar 👇 Rhea is Head of Systems Engineering at BlueCove where she leads a team of Engineers focussed on deliveries to scale the firm across various business lines and building the systems through which BlueCove’s firmwide investment process runs. Prior to joining the firm in 2019, Rhea worked as a Software Engineer at Goldman Sachs from 2013 - 2019 in Controllers Technology and Investment Banking Technology, latterly as Vice President of Debt Capital Markets Technology. Rhea received her Masters of Engineering in Computer Science from Imperial College London in 2013. Can’t wait to hear from her! This evening will be a fantastic opportunity to reconnect with others in the space, meet new faces, and hear directly from some of the talented women in BlueCove’s Engineering and Quant Research teams as they share their technical insights and career journeys. 💡 About BlueCove: Founded in 2018, BlueCove is a scientific asset management firm bringing together leading investment and engineering professionals to research, develop and deploy state-of-the-art scientific investment processes in fixed income management. 📅 Date & Time: Tuesday 11th November, from 6pm 📍 Location: Mayfair, London We have a few spots left - email events@durlstonpartners.com ASAP to register your interest. …more', '6mo • Edited • 6 months ago • Edited • Visible to anyone on or off LinkedIn', 22, 2, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7382082117247148032/', 'Great to have Marcus with the team in Dubai this week! Lots of exciting things happening across the UAE, and globally our teams are firing on all cylinders. Due to continued client demand, we’re still looking to speak with experienced recruiters in our space (or those with a real interest in the quant, tech, and trading world). We work with some of the most innovative hedge funds, prop shops, trading firms, and fintechs globally - and offer the kind of platform, client base, and commission structure that lets strong recruiters thrive (and do well quickly). If you’re curious to learn more, drop me a message for a confidential chat. hashtag#TeamDP hashtag#Hiring hashtag#Dubai hashtag#London hashtag#NewYork hashtag#Quant hashtag#Tech hashtag#Finance hashtag#Recruitment …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 15, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7381676866564419584/', 'The hedge fund scene in the UAE has exploded, now over 150 funds across Dubai and Abu Dhabi, and we’ve been lucky to help build many of them. We are proud to host our heavily sponsored 100 Hedge Funds Event in Dubai and Abu Dhabi on the following dates: 🏝 Dubai (DIFC) 6th of November at 18:00 🏝 Abu Dhabi (ADGM) 19th of November at 18:00 For more information, the latest news and opportunities across hedge funds, family offices, sovereign wealth fund, defence and AI please connect/follow Jared Wolfaardt …more', '6mo • Edited • 6 months ago • Edited • Visible to anyone on or off LinkedIn', 16, 1, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7381587725390495744/', 'Over the past few years, Durlston Partners has been proud to help build and scale many of the region’s leading hedge funds - now numbering over 150 across Dubai and Abu Dhabi. Next month, we’re excited to be hosting our 100 Hedge Funds Event, taking place in both cities: 📍 Dubai (DIFC) – 6th November, 18:00 📍 Abu Dhabi (ADGM) – 19th November, 18:00 These events bring together some of the brightest minds across hedge funds, family offices, sovereign wealth funds, defence, and AI - and promise to be great evenings of conversation and connection. For more information, the latest updates, and opportunities in the space, follow Durlston Partners or drop me a message! …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 20, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7381354753680777216/', '🚨 𝐇𝐢𝐫𝐢𝐧𝐠: 𝐒𝐞𝐧𝐢𝐨𝐫 𝐅𝐫𝐨𝐧𝐭 𝐎𝐟𝐟𝐢𝐜𝐞 𝐐𝐮𝐚𝐧𝐭 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 (𝐃𝐚𝐭𝐚 & 𝐀𝐧𝐚𝐥𝐲𝐭𝐢𝐜𝐬) - 𝐅𝐢𝐱𝐞𝐝 𝐈𝐧𝐜𝐨𝐦𝐞 🚨 📍 𝐋𝐨𝐜𝐚𝐭𝐢𝐨𝐧: London 🏢 𝐖𝐨𝐫𝐤 𝐒𝐭𝐫𝐮𝐜𝐭𝐮𝐫𝐞: Onsite, Front Office 💰 𝐁𝐮𝐝𝐠𝐞𝐭: Open (around £250K TC, bonus buy-outs possible) ⏰ 𝐔𝐫𝐠𝐞𝐧𝐜𝐲:They’d have liked this person to start yesterday - non-compete waits won’t work here. 𝐖𝐡𝐚𝐭 𝐓𝐡𝐞𝐲''𝐫𝐞 𝐥𝐨𝐨𝐤𝐢𝐧𝐠 𝐟𝐨𝐫: 🎯 Proven experience working directly in a front office environment 🎯 Exceptional communication skills - confident engaging with PMs, Quants, and Traders 🎯 Deep understanding of Fixed Income, Rates, and Bonds 𝐖𝐡𝐚𝐭 𝐲𝐨𝐮’𝐥𝐥 𝐝𝐨: 🎯 Partner with PMs, analysts, and traders to design and deliver scalable, high-performance data and analytics solutions 🎯 Build and maintain real-time and batch data pipelines across internal and external sources 🎯 Deploy and optimise workflows in AWS, leveraging Docker and containerized systems 🎯 Handle large-scale financial datasets using Python, Snowflake, and NoSQL (e.g. MongoDB) 🎯 Ensure data quality, integrity, and availability across the front-office stack 🎯 Provide front-line production support, monitoring pipelines and responding to incidents in real time If you’re a front office quant developer who thrives under pressure and loves working close to the action, this one’s for you. 📩 DM me if you’re interested or know someone who might be a great fit. Louis Esquerré-Gow hashtag#hiring hashtag#quantdeveloper hashtag#fixedincome hashtag#frontoffice hashtag#london hashtag#python hashtag#dataengineering …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 13, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7381261421378187264/', 'Just back from an amazing long weekend in Tuscany celebrating a friend’s wedding! Back in action this week and there’s lots of exciting stuff going on at DP - clients are super active and the team’s firing on all cylinders. If you’re a candidate in our space (tech, quant, AI/ML, or digital assets) and open to exploring new opportunities, drop us a note at hello@durlstonpartners.com - one of the team will be in touch if we’re working on something relevant. We’re also partnering with BlueCove on our next Women at the Table event in Mayfair next month - if you’d like to join, email events@durlstonpartners.com to register your interest. And finally, we’re hiring! If you want to join the best team (with offices in London, Dubai and New York), where you’ll plug into warm desks, amazing clients, and an industry-leading commission and incentive structure - drop me a message for a confidential chat. hashtag#DurlstonPartners hashtag#Hiring hashtag#Finance hashtag#Quant hashtag#AI hashtag#WomenAtTheTable hashtag#TeamDP …more', '6mo • Edited • 6 months ago • Edited • Visible to anyone on or off LinkedIn', 12, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7381247255044923392/', 'This week at Durlston Partners, we have 200+ of the best opportunities across Software Engineering, Portfolio Management, and Quant Trading. With offices in London, New York, and Dubai, we’re often the first to hear about the latest and most exciting projects across AI, Family Offices, Hedge Funds, HFTs, Crypto Trading, and Defence. This week, I’m looking to speak with anyone interested in the following opportunities: Full Stack Engineer for a Defence for Good client in London C++ Engineer (Fully Remote) for an HFT client Data Engineers for a Sovereign Wealth Fund client Please connect or follow for the latest opportunities and news Dana Bahram …more', '6mo • Edited • 6 months ago • Edited • Visible to anyone on or off LinkedIn', 16, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7379801711684657152/', 'Having spoken to countless engineers over the years, it’s clear that the best people don’t just want a job - they want a challenge. That’s one of the reasons I’ve enjoyed working closely with firms in the Trading (and now also Crypto and AI) space. These industries are unique. They demand world-class engineering, they move incredibly fast, and they constantly push people to think in ways they haven’t before. The bar is high, but so are the rewards. I’m currently working with a handful of elite firms in London hiring Python & C++ Software Engineers. You’ll be exposed to high-performance systems where every millisecond counts, solving deep technical challenges with some of the brightest minds around. These environments are fast-paced, meritocratic, and your impact will be immediate. These firms are ideally looking for: ✔️ Strong academic background (e.g. Degrees/PhDs from top global universities) ✔️ Proven experience in demanding environments (Trading, Crypto, AI, start-ups, etc.) ✔️ A genuine passion for technology. Someone who doesn’t see the job as just writing code, but has an interest in solving problems, experimenting with new ideas, and pushing the limits of what’s possible ✔️ A mindset for impact If you’re interested, please feel free to reach out to me directly on LinkedIn, or email me: david@durlstonpartners.com https://lnkd.in/ewa3SMrc …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 25, 2, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7379174368595161088/', '𝐔𝐫𝐠𝐞𝐧𝐭 𝐇𝐢𝐫𝐞 - 𝐃𝐚𝐭𝐚 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 – 𝐌𝐚𝐜𝐫𝐨 𝐅𝐚𝐦𝐢𝐥𝐲 𝐎𝐟𝐟𝐢𝐜𝐞 – 𝐍𝐞𝐰 𝐘𝐨𝐫𝐤 We are working with a family office in New York hiring a Data Engineer to build and scale data infrastructure for researchers and trading teams. The role covers building data infrastructure for research, risk, and live trading in a macro finance environment. Candidates should have experience in a tier-1 hedge fund or investment bank. ◾ Market & trading data pipelines ◾ Economic & alternative data integration ◾ Time-series storage & analytics ◾ Risk & PnL systems ◾ Research & model deployment 📍 Location: hashtag#NYC 💰 Comp: Competitive For details on team structure, roadmap, and scope, reach out to me at Xander Oliver / xander@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 15, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7379173266361327617/', '🎉 Happy birthday and happy first week at Durlston Partners to David Ezihe! David joins our Technology team, bringing 6+ years of experience working with some of the most innovative companies across Europe, the US, APAC, and Canada. With a particular focus on the systematic trading space, he’s supported talent across infrastructure, information security, and complex software development. Known for his calm, thoughtful approach, he’s built a reputation for forming long-term partnerships with both clients and candidates. He’s had a great first few days settling in with the London team, and we’re excited to have him on board. We’re still looking to bring on more exciting people in our space due to client demand. At Durlston Partners, we specialise in tech, quant, AI/ML and digital assets, working with some of the most exciting hedge funds, prop shops, trading firms, and fintechs globally. New joiners ramp quickly thanks to warm desks, deep client relationships, and an exceptional platform. If you’re an experienced recruiter curious about joining us in London, Dubai or New York - where you’ll bill big, and be properly rewarded – drop me a message for a confidential chat. hashtag#TeamDP hashtag#Hiring hashtag#Recruitment hashtag#Tech hashtag#Quant hashtag#Finance …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 30, 6, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7379075034146938880/', 'Another great Run Club last night – the sun (and temperature) gods were definitely on our side! 🌞 Always such a good way to catch up with market peers while getting some exercise in and making the most of these lighter evenings before autumn / winter properly kick in! If you’d like to join the next one, you can sign up to our community here: https://lnkd.in/etjTFPex hashtag#RunClub hashtag#FinanceAndTech hashtag#Community hashtag#NetworkingButFun hashtag#TeamDP …more', '6mo • Edited • 6 months ago • Edited • Visible to anyone on or off LinkedIn', 17, 0, 1, 'image', 0, NULL, 29934);
