INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7378787485528662016/', 'We took Jet2''s summer viral trend, and turned it into a physical must-have hype shirt. And then of all the places to launch it… we dropped it at London Fashion Week. 🤭🤭🤭 Design ✅/ Production✅ / Social ✅/ Influencer ✅/ Press ✅ / PR ✅ Fast and nimble, what a team, thank you 👏👏👏 Aimee Nazroo Ellie Moss Jessica Jordan-Wrench Owain Davies Lewis Oliver Josh Pinard Sophie Berman Maria Sihaloho Amber Dodds Nick Wright Lu Howlett hashtag#LimitedEdition hashtag#Creative hashtag#Influencers hashtag#Pr hashtag#Press hashtag#Hype …more', '6mo • Edited • 6 months ago • Edited • Visible to anyone on or off LinkedIn', 70, 0, 6, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7378698096827932672/', '☀️ Bright sunshine all day and set for a beautiful evening for our Run Club tonight! We’ll be meeting at 6pm at DP London HQ for a bag drop and heading out around 6:15pm (if you’re running a little late, don’t worry - we’ll share a number so you can catch us on the route). It’s a scenic Royal Parks loop followed by a well-deserved pint (or non-alc bev) at one of our locals. 🍻 If you’re in the area with your gym kit and fancy making the most of the September sun, come and join us! Drop me a message or grab one of the final spots here: https://luma.com/pzqn2im0 …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 9, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7375926222444462084/', '🎉 Happy birthday to me! Great start to the week with the team and feeling full after a massive Bruce Bogtrotter cake ❤️ 🎂 & the sun is out ☀️ It’s an exciting week of conversations with some fantastic candidates, onboarding and training two new starters, and looking forward to welcoming a third next week. At Durlston Partners, we partner with some of the most exciting names in the FinTech space, helping clients hire the best talent and candidates make their next big move. If you’re a potential client looking to hire, or a candidate considering your options, drop us a note at hello@durlstonpartners.com. And if you’re a recruiter looking to join the best team in London, New York, or Dubai, message me directly. …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 77, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7374797875223998464/', 'Beautiful day in the most beautiful city 🌞& it''s bring your sister to work day (after an amazing night seeing Lewis Capaldi 🎶) - sunshine lunches all around! I’m having some brilliant conversations with exceptional candidates globally, and we’re always keen to connect with the very best in our space. We’re growing organically, with two new starters joining us this week in Dubai and New York – lots of exciting things ahead. Want to join us? Drop me a message! hashtag#Hiring hashtag#Recruitment hashtag#Quant hashtag#Tech hashtag#TeamDP …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 8, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7374359903404208128/', 'The countdown is on! 🚀 Our next run is just around the corner, and the buzz is real after our amazing first event. Get ready to lace up and hit the pavement again on Wednesday, 30th September! Here are the key details: 𝗧𝗶𝗺𝗲: Meet 6pm sharp 𝗠𝗲𝗲𝘁𝗶𝗻𝗴 𝗣𝗼𝗶𝗻𝘁: Durlston Partners office (Bag Drop) 𝗥𝗼𝘂𝘁𝗲: A scenic loop around St James’s & Green Park. 𝗣𝗮𝗰𝗲: A relaxed, chatty pace. Everyone is welcome, no matter your speed. 𝗣𝗼𝘀𝘁-𝗥𝘂𝗻: We''ll refuel with a pint at a nearby pub, hope you can join! Sign-up: https://luma.com/pzqn2im0 I can''t wait to see you all there for another great one! Let''s go! 🏃‍♀️🏃‍♂️ …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 12, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7374079310464307201/', 'Women at the Table is back, and this time we’re teaming up with BlueCove! Join us for an evening of great conversation, fresh connections, and real technical and career insights from women at the forefront of quant research and engineering. BlueCove is a scientific asset management firm founded in 2018. BlueCove brings together leading investment and engineering professionals to research, develop and deploy state-of-the-art scientific investment processes applicable to fixed income management. You can find out more about BlueCove on their website: https://www.bluecove.com/. We’re thrilled to be partnering with them for this one. Spaces are limited – email events@durlstonpartners.com to register your interest. …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 8, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7373970848879251456/', 'Women at the Table is back, and this time we’re teaming up with our neighbours in London, BlueCove! Join us for good conversations, new faces, and honest insights from women building careers in quant research and engineering. Founded in 2018, BlueCove is a systematic fixed income hedge fund with an outstanding culture in engineering, learning and development. We’re thrilled to be partnering with them for this one. Spaces are limited – please email events@durlstonpartners.com to register your interest. Hopefully goes without saying but no dudes! …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 11, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7373312683737243648/', 'Women at the Table is back, and this time we’re teaming up with BlueCove! Join us for an evening of great conversation, fresh connections, and real technical and career insights from women at the forefront of quant research and engineering. BlueCove is a scientific asset management firm founded in 2018. BlueCove brings together leading investment and engineering professionals to research, develop and deploy state-of-the-art scientific investment processes applicable to fixed income management. You can find out more about BlueCove on their website: https://www.bluecove.com/. We’re thrilled to be partnering with them for this one. Spaces are limited – email events@durlstonpartners.com to register your interest. …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 19, 0, 2, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7371811747806232576/', 'After the success of our very first Run Club, we’re bringing it back – next one is Monday 30th September! It’s a relaxed, social way to bring together people from across FinTech, hedge funds, quant, and AI – swapping screens for trainers and connecting outside the usual meeting rooms. All levels welcome (genuinely) – this is about conversation, not competition. The vibe at the last one was brilliant, and we’re excited to do it all again. All the details are in the Durlston Partners Run Club group – link in the comments if you’d like to join us. Daniel Frugtniet Hagen Teagan Hill https://lnkd.in/etjTFPex Lace up, come along, and let’s make this one even bigger. 🏃‍♀️🏃‍♂️ hashtag#RunClub hashtag#FinanceAndTech hashtag#NetworkingButFun hashtag#TeamDP …more', '7mo • Edited • 7 months ago • Edited • Visible to anyone on or off LinkedIn', 22, 3, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7371530319214161922/', 'Perk of braving the strikes and getting into the office today? Just gave Louis Theroux a hug right outside our office. Pretty sure he stopped because I said his name with such familiarity he thought I actually knew him 😂 No selfie… but ChatGPT has kindly recreated the moment for me (although I was a lot sweatier post lunchtime 5k). If you fancy working on the best street in London (Regent Street), with warm desks, great clients, a brilliant team, amazing incentives / comp, and an occasional celeb spot, hit me up. We’re hiring! shannon@durlstonpartners.com …more', '7mo • Edited • 7 months ago • Edited • Visible to anyone on or off LinkedIn', 42, 3, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7371525758042677248/', 'Our first run club was a massive success, so we''re doing it again on September 30th! This is a space for professionals in FinTech, Hedge Funds, Quant, and AI to connect beyond the desk in a refreshing way. All fitness levels are welcome; it''s about connection, not competition. The energy at the last event was incredible, and we''re buzzing for the next one. 🚀 Want in? All info for the next run is in the Durlston Partners Run Club group. Join via the link in the comments. Lace up and we''ll see you there. 🏃‍♂️🏃‍♀️ hashtag#durlstonpartners hashtag#runclub hashtag#networking hashtag#finance hashtag#technology hashtag#hedgefund hashtag#trading hashtag#london …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 17, 1, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7371455273900679168/', '🚀 We’re hiring in London and Dubai. At Durlston Partners we partner with some of the most exciting names in the fintech, quant and AI/ML space. New joiners hit the ground running thanks to warm desks and long-standing client relationships. What sets us apart? A commission structure that genuinely rewards performance (10-40% with no desk fees, thresholds or draws), extra incentives for new business, meaningful profit share and equity, plus perks like private health & dental, wellness allowances, two bonus weeks off over Christmas, regular socials and international trips. We’re ambitious and high-performing, but also collaborative and fun - the kind of place where you’ll learn fast, earn well, and enjoy coming to work. We’re looking for experienced consultants (3+ years) in tech or quant recruitment who want to take their career to the next level, as well as juniors with 1–3 years’ experience who are curious, driven and keen to plug into a strong platform. If you’re ready to bill big, earn big and be properly rewarded, drop me a message for a confidential chat. shannon@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 14, 1, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7371181062212825089/', 'L is the letter of the week in London: Legs, Limes and Lizzie Line (modes of transport) Loyle Carner (travel soundtrack) Leon (daily breakfast order for those who made it in) Lucky to live close to the Lizzie Line, which takes me straight into Bond Street - nice to see everyone out on the lime bikes in the sun, too. Managed a peaceful 5k around the Royal Parks at lunch - fewer tourists to dodge than usual, though dodging the mounds of lime bikes parked on every corner is a new skill. Glass-half-full kind of gal, and it’s been an enjoyable, focused week so far in a slightly quieter office. The market certainly hasn’t slowed down - we’re busier than ever and hiring across Python, C++, Java, Rust, data, and DevOps, as well as quant researchers, strategists, and ML/AI specialists globally. We’re also on the lookout for a quant recruiter for a growing systematic fund in the US and agency recruiters in London / Dubai / NY who want to plug into one of the strongest platforms in the market. If that’s you (or someone you know), drop me a message - always happy to chat. Referrals are welcome and well rewarded. Shannon@durlstonpartners.com hashtag#London hashtag#Hiring hashtag#Recruitment hashtag#Quant hashtag#Tech hashtag#Strikes …more', '7mo • Edited • 7 months ago • Edited • Visible to anyone on or off LinkedIn', 13, 0, 0, 'video', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7370739334788067328/', 'Kicked off the week with a 6k run into the office (a planned 2.5k to the Lizzie Line turned into a 6k detour thanks to TCR/Bond Street station closure 🙃). Beautiful morning for it though, and it ticks off run #1 of the week. For September, I’m aiming for 35k a week (about 5k a day) - managed 40k last week and even squeezed in a Bristol parkrun on a hen do (hen’s request, she’s a serious park-runner!). Lucky to get most of my kilometres in on my lunch breaks with the Royal Parks on our doorstep. Just as lucky to have a proper office set-up where I can work flat out during the day, then fully switch off in the evenings. Anyone else with me on preferring the office to WFH? Lots going on at DP right now: 👉 Tech - We’re hiring across Python, C++, Java, Rust, frontend, data and DevOps... from backend engineers to low-latency C++ developers and data scientists, with roles spanning New York, London, Chicago, Abu Dhabi, Dubai and beyond. 👉 Quant - On the quant side, we’re working on everything from junior researcher roles to senior strategist positions, as well as ML/AI specialist opportunities across London, Singapore, New York, Chicago, Amsterdam and APAC. 👉 Recruiters - hiring a Quant Recruiter in the US (fully remote, excellent comp), plus agency recruiters for London/Dubai who want to plug into one of the best platforms in the market. 👉 Women at the Table - our next event will be in November, details coming soon. Email events@durlstonpartners.com to get on the list. If you’re in the market (or know someone who is), drop me a message. hello@durlstonpartners.com hashtag#Hiring hashtag#Quant hashtag#Tech hashtag#Recruitment hashtag#RunClub hashtag#WomenAtTheTable …more', '7mo • Edited • 7 months ago • Edited • Visible to anyone on or off LinkedIn', 11, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7370737467336847360/', 'Tired of hearing about boring software engineering roles? I''m working with a top-tier quantitative firm in London that''s looking for a Software Engineer to join their team. This is a opportunity to tackle complex challenges at the intersection of technology and finance. You''ll partner directly with quantitative researchers to build and implement high-performance trading systems that are put to the test in live markets. They''re looking for a professional with: - 4+ yrs of experience in either C++ or Python. - A genuine passion and understanding of financial markets. - A drive to engineer robust, scalable, and mission-critical systems. If you''re ready for a challenging role where you can make a significant impact, I''d like to hear from you. Send me a DM for a confidential chat. daniel@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 8, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7369634725734395904/', 'Forever grateful to walk into our Regent Street office every morning - one of the most iconic streets in London. Lots of exciting things happening across all our offices (London, Dubai, and New York). On the tech side, we’re hiring across Python, C++, Java, Rust, frontend, data and DevOps - with opportunities ranging from backend engineers in New York, to low-latency C++ developers in London and Chicago, to data scientists and trading systems engineers in Abu Dhabi (and everything in between). Roles span hedge funds, trading firms, and fintechs, with generous compensation packages. On the quant side, we’re working with global trading firms and hedge funds on everything from junior researchers in London and Singapore, to senior quant strategists in New York and Chicago, to ML/AI specialists in London, Amsterdam, and APAC. Lots of variety, from crypto quant trading to cutting-edge NLP and deep learning research. On the recruiter side: 📍 Quant Recruiters in the US: I’m hiring on behalf of a rapidly scaling global trading firm who are fully remote. They’re looking for an exceptional recruiter with a strong network of Traders and QRs. Fully remote, but you’ll need to be US-based. Great comp and performance-based bonuses. 📍 Agency recruiters: We’re also hiring at Durlston Partners. If you’re looking to join the best team in London, plug into an exceptional platform, and bill big from day one (no thresholds, no desk fees, no caps), drop me a message. Women at the Table: we’ll soon be announcing our next event this November in partnership with one of our clients. If you’d like to be added to the invite list, email events@durlstonpartners.com. Big few months ahead - excited for what’s coming! As always, referrals welcome (and well rewarded). hashtag#Hiring hashtag#Quant hashtag#Tech hashtag#AI hashtag#RecruitmentCareers hashtag#WomenAtTheTable hashtag#DurlstonPartners …more', '7mo • Edited • 7 months ago • Edited • Visible to anyone on or off LinkedIn', 13, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7369381582551277569/', 'Now that the London weather has turned (what is happening out there?), a new DP activity has been unlocked! We always encourage the team to take proper breaks away from their desks... mid-morning and afternoon walks, longer lunches for the gym or exercise etc.. But when it’s a bit too temperamental outside, we’ve got plenty going on indoors: 🏓 Table tennis 🎯 Darts♟️ Chess 🃏 And now… cards...(SHEAD specifically). Managed to thrash Jimbo twice on his own rules earlier 🙌 Question is… what rules do you play? My rules: 2 (back to the start), 3 (invisible), 7 (played chronologically but next player plays below), 10 burns the pack Jimbo''s rules: 2 (back to the start), show a 3 (other player picks up), 7 (invisible), 8 (play below it), 10 burns the pack If you want to come and challenge me to a game OR fancy joining the best team in London / Dubai / NY, have access to an exceptional platform, bill and earn big from day 1 with no desk fees, no thresholds, uncapped commission, loads of cash incentives, and have a laugh (/ card game or two) along the way, drop me a message - we’re hiring. Monopoly deal next? …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 11, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7369041480918736898/', 'Quant Recruiters in the US, this one’s for you. I’m working with a rapidly scaling global trading firm who operate fully remotely - they''re looking for an exceptional Quant Recruiter with a strong network of Traders and QRs. This role is fully remote but requires you to be based in the US. Compensation is very competitive, with strong performance-based bonuses on top. Open to speaking with both experienced agency recruiters and those working internally who might be curious! If this sounds like you (or someone you know), please get in touch. Referrals are always welcome, and well rewarded. …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 5, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7368640109547556864/', 'We had the amazing Paris Norriss in the office last week for a talk on grit and resilience – and the team were hooked. In 2025, Paris broke records by running seven marathons across seven continents in just 5 days and 21 hours – despite having only ever run one marathon before. This came not long after he rowed 4,800km across the Pacific Ocean in 2023, raising £150,000 for marine conservation. Through The Grit Code, Paris turns these extreme challenges into practical lessons on thriving under pressure, pushing limits, and staying resilient – themes that couldn’t be more relevant to the work we do at Durlston Partners. It was inspiring, motivating, and a great reminder that grit and determination are the foundation for success in every area of life. If your team could use a dose of perspective and motivation, I’d highly recommend reaching out to Paris. hashtag#Resilience hashtag#Motivation hashtag#GritCode hashtag#TeamDP hashtag#Inspiration …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7364581887618490369/', 'If you missed our first Industry Run Club but want to be part of the next one, drop a note to events@durlstonpartners.com and we’ll keep you posted once the next date is locked in.🏃‍♀️🏃‍♂️ hashtag#RunClub hashtag#FinanceAndTech hashtag#NetworkingButFun hashtag#DurlstonPartners hashtag#TeamDP …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 6, 0, 1, 'video', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7364250008616853505/', 'An absolutely brilliant evening yesterday for our very first Industry Run Club. Perfect weather, beautiful views, and even better conversations - a great mix of reconnecting with familiar faces and meeting new ones across the finance and tech space. If you’d like to join us next time, drop a note to events@durlstonpartners.com and we’ll make sure you’re on the list for future events. Huge thanks to Daniel Frugtniet Hagen for sparking the idea and leading the initiative, and to Louis Esquerré-Gow and Teagan Hill for their support in making it happen. …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 19, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7364207490009296898/', 'What a fantastic turnout for our first run club last night! 🏃‍♂️🏃‍♀️💨 A huge thank you to everyone who joined and brought such great energy. It was amazing to connect with you all. A special shout out to Shannon Palmer for being an absolute rockstar and helping to organize everything. Couldn''t have done it without you! And a big thank you to Louis Esquerré-Gow and Teagan Hill for helping out too! We''re already buzzing with ideas for the next one. Keep your eyes peeled for an announcement coming soon! 🚀 hashtag#runclub hashtag#finance hashtag#tech hashtag#networking hashtag#london …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 27, 2, 2, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7363842079753412608/', 'Weather is looking perfect (20 degrees & sunny) for our very first Industry Run Club this evening ☀️👟 If you haven’t registered but fancy joining, we’d still love to have you... just drop me a message here or email shannon@durlstonpartners.com. 📍 Meeting at the DP London office 🏃‍♀️ Scenic loop through St James’s & Green Park at a relaxed, talking pace (all levels welcome) 🍻 Optional (but encouraged!) post-run drink It’s free to join, super informal, and a great way to get some fresh air, catch up with colleagues, and meet others from across the quant, tech, AI/ML, and digital assets space. See you at the start line! https://lnkd.in/e_6x2YUb …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 8, 0, 1, 'article', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7363510069361041409/', '** 𝐄𝐱𝐜𝐥𝐮𝐬𝐢𝐯𝐞 𝐌𝐚𝐧𝐝𝐚𝐭𝐞 ** 𝟐𝐱 𝐏𝐲𝐭𝐡𝐨𝐧/𝐂# 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫𝐬 - 𝐁𝐨𝐮𝐭𝐢𝐪𝐮𝐞 𝐅𝐮𝐧𝐝 - 𝐔𝐩 𝐭𝐨 £𝟐𝟎𝟎𝐤 𝐓𝐂 - 𝐋𝐨𝐧𝐝𝐨𝐧 One of London''s best performing Hedge Funds, is looking to add two Engineers to their Middle Office/Core Team. Must haves: ✅Excellent Python skills ✅Basic C# knowledge (can work with request/response queries) ✅CompSci background (must have excellent core Software Engineering skills) ✅Good attitude to code testing/reviews, especially for deploying critical code For more information, please get in touch at james@durlstonpartners.com hashtag#Python hashtag#CSharp hashtag#SoftwareEngineering hashtag#MiddleOffice hashtag#Trading hashtag#Risk hashtag#LondonJobs hashtag#hedgefunds hashtag#Compsci …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 17, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7363136954948878338/', 'Looking like perfect running conditions for our very first industry run club this Wednesday! ☀️🏃‍♀️🏃‍♂️ If you’d like to join us but haven’t registered yet, you can sign up via the Eventbrite link below 👇 All levels are welcome - it’s a relaxed, social run followed by a well-deserved drink afterwards 🍻 A great way to get your steps in, get the blood pumping, and have some interesting chats with people across the industry... whether that’s catching up with colleagues or making new connections. Any questions at all, just drop me a message! https://lnkd.in/e_6x2YUb …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 7, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7363117372418760706/', 'Feeling spoiled by the UK weather this summer! The "return to UAE countdown" is now at T-10 days after moving flights back; would be rude not to stick around for the UK Aug BH weekend with skies like this. Durlston Partners …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 24, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7362396459503161344/', 'Happy Saturday! 🌞 This will be the view next Wednesday evening if you join us for our very first industry run club 🏃‍♀️🏃‍♂️ We’re bringing together people from across the quant, tech, AI/ML, and digital assets sectors for a relaxed, social run – a chance to get some fresh air, see a bit of London, and connect with others in the industry. 🕡 Departure from DP London at 6.30pm 🏞 Route: Scenic loop through St James’s & Green Park at a talking pace – all levels welcome 🍻 Post-run: Optional drink at a local pub It’s completely free – just register via the link below so we know to expect you. https://lnkd.in/e_6x2YUb …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7362018609650405376/', '♟ Checkmate. How do you connect with your recruiters? Siva Keefe Savero’s been mixing things up - taking on clients and candidates at chess (and occasionally schooling some of the DP team in the office too). Last week we caught up with a client by racing cars at the F1 Arcade, and next week we’re hosting our first-ever industry Run Club. So whether you’re into chess, F1, running… or just an old-fashioned drink outside a packed pub in central London, we’re here for it. The weather’s looking hot for the next couple of weeks... if you fancy meeting up, drop us a line. Run Club is next Wednesday eve... link below if you want to join us. 🏃‍♀️🏃‍♂️ https://lnkd.in/e_6x2YUb Durlston Partners hashtag#Chess hashtag#F1 hashtag#RunClub hashtag#FinanceAndTech …more', '8mo • Edited • 8 months ago • Edited • Visible to anyone on or off LinkedIn', 21, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7361395593132314625/', 'T-minus 1 week until our market 5k run! Mixing up the usual post-work routine with something a bit different… join us for the very first Durlston Partners Run Club 🏃‍♀️🏃‍♂️ A relaxed, social run to bring together people from across the finance and tech space! 🗓 Date: Wednesday 20 August ⏰ Time: 6:30pm 📍 Route: Scenic loop around St James’s & Green Park 👟 Pace: Talking pace - genuinely all levels welcome 🍻 Post-run vibes: Optional (but encouraged) pint at The Devonshire It’s completely free, super low-key, and open to anyone in the industry who fancies doing something a bit different after work. Want to join? Register via EventBrite (link below): https://lnkd.in/evzegfgn …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 7, 1, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7361386618328367106/', 'T minus 2 weeks until the very first DP / industry Run Club! 🏃‍♀️🏃‍♂️ We’re swapping the usual post-work routine for something a bit different… a relaxed, social run to bring together people from across the finance and tech space. 🗓 Wednesday 20 August ⏰ 6:30pm 📍 Scenic loop around St James’s & Green Park 👟 Talking pace - all levels welcome 🍻 Post-run drink at The Devonshire (optional… but encouraged) According to the 2-week forecast, it’s looking like sunshine - so if you fancy getting some fresh air, meeting great people, and earning your midweek pint, we’d love to have you join. It’s completely free and open to anyone in the industry, just register below (link in comments). Tag a friend or colleague who should be on that start line with you 👇 …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 12, 3, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7361338336738742272/', 'Due to exceptional client demand, we’re looking for an experienced Quant Recruiter to join the Durlston Partners team. Ideally, you’ll have 2–3+ years’ experience placing into HFTs, prop shops, or other buy-side firms. We want someone who’s hungry, collaborative, and ready to make placements - and be well rewarded for it. We partner with some of the most exciting names in the industry, covering quant, tech, data, AI/ML and digital assets. We work with hedge funds, HFTs, prop shops, fintechs and asset managers globally, with offices in London, New York, and Dubai. Offer genuinely warm desks, deep client relationships, and the platform to set you up for success from day one. You’ll get: market-leading commission with no thresholds, caps, or desk fees, meaningful profit share, cash BD incentives and bonuses, top-tier clients and no internal restrictions on access to them, support to shape your growth, perks like a two-week Christmas break, BUPA cover, £1,200 wellness/phone allowance, regular socials, and global incentives. If this sounds like you or someone you know, drop me a message or email shannon@durlstonpartners.com for a confidential chat. …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 13, 0, 3, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7360938331947290624/', 'Thinking about moving to the UAE? 🇦🇪✈️🌎 We speak to women every week who are thinking about moving to Dubai or Abu Dhabi for a career in tech or finance, and we hear the same question: "What’s it really like?" As part of our Women at the Table initiative, we want to get to the heart of your questions and share answers directly from women who’ve already made the move. We’d love to hear from you: What’s your biggest question about living and working in the UAE? Your input will help shape upcoming interviews with incredible women in the region. Have a question that’s not listed? Let us know in the comments. 💬 hashtag#WomenAtTheTable hashtag#WomenInTech hashtag#WomeninFinance hashtag#UAE hashtag#Relocation …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 15, 0, 5, 'poll', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7360658703227731969/', 'The countdown’s on... our first Durlston Partners Market Run is next week! (or Shan’s sightseeing tour of London 🏛️) Snapped these pics on today’s lunchtime run - it’s an absolute scorcher out there, and the route is looking stunning. 🗓 Wednesday 20 August ⏰ 6:30pm 📍 Scenic loop around St James’s & Green Park (with a Buckingham Palace cameo) 👟 Talking pace - all levels welcome 🍻 Optional (but encouraged) pint at The Devonshire after Fresh air, good chat, and a midweek pint you’ve truly earned... what’s not to love? It’s completely free and open to anyone in the finance and tech space. Register via the link below and tag a colleague who should be there with you 👇 https://lnkd.in/e_6x2YUb …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 16, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7360579231384281088/', 'Hit the track (virtually) last week with a client and some of the Durlston Partners team at the F1 Arcade! Always great to catch up in person with the people we’re collaborating with day-to-day, and to mix in a bit of (competitive) fun along the way. We’ve got some big F1 fans in the team, and turns out quite a few of our clients are just as passionate about fast cars! At Durlston Partners, building meaningful partnerships with both our clients and candidates is at the heart of what we do. For us, it’s about understanding people, building trust, and delivering results - whether that’s placing exceptional talent or helping clients grow world-class teams. If you’re hiring at your firm and think we could add value, a candidate looking for your next role, or a recruiter wanting to join the best team in London, drop me a message. …more', '8mo • Edited • 8 months ago • Edited • Visible to anyone on or off LinkedIn', 15, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7359168906646691841/', 'Fancy a relocation to Dubai? ☀️🌴 4 of our London team have made the move over the last few years and haven’t looked back... the sunshine is guaranteed, and the tax-free comp is life-changing. We’re urgently looking for someone to join our Dubai team, driven by exceptional client demand across tech and quant finance. You could already be based in Dubai, start in London with a plan to relocate, or we can support a move right away. At Durlston Partners, we’re a high-performing team of 21 with offices in London, New York and Dubai. We work with the most exciting names in tech & trading, hedge funds, HFTs, asset managers, prop shops and fintechs, placing across quant, tech, data, AI/ML, and digital assets. We offer market-leading commission (no desk fees or thresholds), BD incentives, bonuses, and meaningful profit share. Full access to clients and roles from day one (no internal politics or restrictions). Warm desks, amazing team culture, training, socials, and global incentives. If you or someone you know might be keen to join the Dubai office, drop me a message or email: shannon@durlstonpartners.com Sharing a few pics from trips to Dubai... next one coming up soon! …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 47, 1, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7358863256142110720/', 'T minus 2 weeks until the very first DP / industry Run Club! 🏃‍♀️🏃‍♂️ We’re swapping the usual post-work routine for something a bit different… a relaxed, social run to bring together people from across the finance and tech space. 🗓 Wednesday 20 August ⏰ 6:30pm 📍 Scenic loop around St James’s & Green Park 👟 Talking pace - all levels welcome 🍻 Post-run drink at The Devonshire (optional… but encouraged) According to the 2-week forecast, it’s looking like sunshine - so if you fancy getting some fresh air, meeting great people, and earning your midweek pint, we’d love to have you join. It’s completely free and open to anyone in the industry, just register below (link in comments). Tag a friend or colleague who should be on that start line with you 👇 …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 12, 3, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7358812095271903232/', 'A big week of celebrations at Durlston Partners! Warwick Poelman (واريك بولمان) hitting 8 years at DP, Jamie Burman promoted to Associate Director, Adam Baard promoted to Associate Consultant, just shy of his 3-month anniversary! All systems go here... despite summer holidays in full swing, the team are flying and the office is buzzing. We’re hiring across the business and looking to bring in ambitious, smart people who want to be part of a high-performing, collaborative team. We work with the most exciting names in hedge funds, HFTs, FinTechs, and trading firms, building world-class teams! ➡️ Warm desks and urgent live mandates from day one ➡️ No internal blockers - full access to clients, roles, and opportunities ➡️ Market-leading commission with no desk fees or thresholds ➡️ BD incentives & meaningful profit share ➡️ Global offices in London, New York, and Dubai (opportunity for Dubai relocation) We also know how to celebrate: incentive trips, two-week Christmas bonus break, top-tier healthcare, team lunches, Deliveroos, and a genuinely great group of people to work alongside. Drop me a message or email shannon@durlstonpartners.com if you want to chat. Even if you’re not actively looking, always happy to speak to great people. …more', '8mo • Edited • 8 months ago • Edited • Visible to anyone on or off LinkedIn', 18, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7358041665527291905/', 'We’re mixing up the usual post-work routine with something a bit different… Join us for the very first Durlston Partners Run Club 🏃‍♀️🏃‍♂️ A relaxed, social run to bring together people from across the finance and tech space! 🗓 Date: Wednesday 20 August ⏰ Time: 6:30pm 📍 Route: Scenic loop around St James’s & Green Park 👟 Pace: Talking pace - genuinely all levels welcome 🍻 Post-run vibes: Optional (but encouraged) pint at The Devonshire It’s completely free, super low-key, and open to anyone in the industry who fancies doing something a bit different after work. Want to join? Register via EventBrite (link below): https://lnkd.in/e_6x2YUb hashtag#RunClub hashtag#FinanceAndTech hashtag#LondonRunClub hashtag#NetworkingButFun hashtag#HedgeFunds hashtag#FinTech hashtag#DurlstonPartners hashtag#TeamDP …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 15, 0, 2, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7357051304386433025/', 'HELP NEEDED: which recruitment platform / ATS / CRM to go for? Hello LinkedIn 👋 I''ve spent the last couple of weeks deep in demos. Moving our team off a system they know and have had for years is a big shift. It could revolutionise the way we work but it could also be disruptive, and no system is perfect. AI, sourcing and automation features are exciting, but are the basics solid? What’s the reality of using these tools day to day? I need to make a decision soon, and I know I’ve got a network full of recruiters - so if you’ve had a great or terrible experience with your ATS/CRM, I’d love to hear about it. Drop me a DM or email shannon@durlstonpartners.com - would really appreciate your advice! 🙏 …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 9, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7357050028290416640/', '📣 Save the Date: August 20th at 6:30pm! We’re excited to host our Durlston Partners Run Club, a chance to unwind, get moving, and connect with others in the quant and tech space. 🏃‍♂️ We''ll take a scenic route through our Mayfair neighbourhood, cutting across Green Park and St James’s Park, and we’ll wrap it all up with a well-earned pint (or Aperol Spritz). Despite talk of a summer slowdown, we’ve seen quite the opposite, so we’ll also share some insights into what’s happening across quant research, data science, and tech hiring. Whether you’re a seasoned runner or just looking to meet like-minded people, we’d love to see you there. Eventbrite link is in the comments! …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 18, 3, 2, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7357046545713618945/', 'Tired of the same old networking events? Let''s switch things up. Here are the details for our first Durlston Partners Run Club, designed to connect the worlds of finance and technology. - 𝗧𝗵𝗲 𝗗𝗮𝘁𝗲: Wednesday, 20 August - 𝗧𝗵𝗲 𝗧𝗶𝗺𝗲: 6:30pm - 𝗧𝗵𝗲 𝗣𝗹𝗮𝗰𝗲: A scenic route around St James Park - 𝗧𝗵𝗲 𝗩𝗶𝗯𝗲: All levels are welcome, whether you''re a seasoned pro or just starting out. - 𝗧𝗵𝗲 𝗚𝗼𝗮𝗹: Combine a bit of fitness with meeting like-minded people. This is your chance to lace up, break a sweat, and make some great connections outside of the office. Ready to join? Register for your free spot in the comments. (The exact meeting point will be emailed to everyone who signs up). See you at the starting line! 🏃‍♂️ P.S. Who are you bringing with you? Tag a friend or colleague from the finance space who shouldn''t miss this! hashtag#runclub hashtag#finance hashtag#hedgefunds hashtag#tech …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 23, 3, 2, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7356224929870008320/', 'We’re hosting our (slightly delayed) End of H1 celebration tomorrow! Part of it is the DPer of H1 award, which is peer-nominated. Every six months, we ask the team to reflect on who’s made a real impact, not just based on deals, but on the qualities that define our culture: Helping others succeed. Being consistent, curious, and kind. Selflessness. Humility. A collaborative mindset. Focusing on the journey, not just the destination. It’s one of my favourite things to read through. The nominations are full of care, thought, and genuine respect, and such a lovely reminder of the calibre of people we have across DP. The votes are incredibly diverse, which says a lot. Different styles, different strengths, but all showing signs of that DP DNA. Shoutout to the entire team for the hard work, consistent effort, and unwavering support for one another. Looking forward to celebrating properly tomorrow 🥂 …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 8, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7355995662301241345/', 'Training this afternoon with the wonder that is Warwick Poelman (واريك بولمان), sharing his wisdom with the team 👏 Am sure everyone took something valuable away - always learning from one another here at DP. Just been going through our DPer of H1 peer nominations, and the things people write about each other are honestly so lovely. It’s a reminder of how much we grow together and how willing everyone is to lend a hand when it matters. If you’re looking to be part of a high-performing, collaborative team that genuinely roots for each other, we’re hiring. Market leading commission, an incredible platform with warm desks for you to plug into and start billing immediately, brilliant consultants globally - London, Dubai, NY! shannon@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 13, 0, 1, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7355588608084299776/', '🏃‍♀️ Market fun run incoming! 🏃‍♂️Durlston Partners are planning a social run for finance + tech folks in August... very relaxed, talking pace, and all running levels welcome. The plan is to meet at our Regent Street office for a quick bag drop, take a stroll down to the top of The Mall, and do a gentle loop around St James’s and Green Park, taking in a few sights along the way (just did a tester run with Daniel and Siva this lunch)! We might even end up at The Devonshire for a cheeky pint as a reward for all that hard work 🍻 If you fancy joining, drop me or Daniel a message, or email shannon@durlstonpartners.com and we’ll get you signed up. hashtag#RunClub hashtag#LondonNetworking hashtag#FinanceRunClub hashtag#MarketMeetUp hashtag#Wellness hashtag#DurlstonPartners hashtag#WorkWithUs …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 17, 0, 3, 'video', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7355512661033295872/', 'We’re always speaking to brilliant people in the market... whether you’re actively looking or just exploring what might be next longer-term, we’re open to having that conversation. We’ve built our business around long-term partnerships, and we know the best moves often come from quiet, early conversations... not when someone’s urgently on the move. That said, we also receive hundreds of messages and applications every day, and as a small team it''s not always possible to respond to everyone. If you''d like to be considered, please email your CV (along with your ideal role and location) to hello@durlstonpartners.com. We’ll make sure it gets in front of the right person (/ people), and if we’re working on something that aligns with your experience, someone will be in touch. We understand the job market is tough right now, and we genuinely do our best to respond to and support as many candidates as we can. We may not always reply immediately, or at all if the timing isn’t quite right, but we’re always building relationships with the long term in mind. And if we don’t end up speaking this time around - wishing you all the best with your search. Have a great week, everyone! hello@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7354517111840382976/', '🚨 London Run Club incoming! We’re putting together a Run Club for finance and tech professionals - a relaxed, no-pressure way to clear your head, stay active, and connect with like-minded people outside of the office. First meet-up is planned for August, and we’ve already got a great mix of people confirmed (top hedge funds, investment banks). Would love for you to be part of it too! If you''re keen (or even just mildly curious), check out the post and cast your vote on when works best: https://lnkd.in/eN-TTP27 …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7354499571114229760/', 'Two incredible weeks here at Durlston Partners. A few senior Quant PMs we represent are on the verge of receiving offers—creative deals are being structured—as the quantitative markets face a turbulent summer. The "long, slow bleed" highlighted in Business Insider has triggered a wave of conversations on both sides. Clients are asking who''s up, who''s down, and how to position themselves in this shifting landscape. At the same time, we''re speaking to an increasing number of top quant PMs, researchers, and technologists who are quietly exploring what''s out there. We are currently actively hiring for 𝐐𝐮𝐚𝐧𝐭𝐢𝐭𝐚𝐭𝐢𝐯𝐞 𝐏𝐨𝐫𝐭𝐟𝐨𝐥𝐢𝐨 𝐌𝐚𝐧𝐚𝐠𝐞𝐫𝐬 (𝐐𝐮𝐚𝐧𝐭 𝐏𝐌𝐬) 𝐚𝐜𝐫𝐨𝐬𝐬 𝐭𝐡𝐞 𝐔𝐒, 𝐄𝐌𝐄𝐀, 𝐚𝐧𝐝 𝐔𝐀𝐄, 𝐚𝐬 𝐰𝐞𝐥𝐥 𝐚𝐬 𝐟𝐨𝐫 𝐦𝐢𝐝-𝐟𝐫𝐞𝐪𝐮𝐞𝐧𝐜𝐲 𝐫𝐞𝐬𝐞𝐚𝐫𝐜𝐡𝐞𝐫𝐬, 𝐬𝐲𝐬𝐭𝐞𝐦𝐚𝐭𝐢𝐜 𝐄𝐓𝐅 𝐭𝐫𝐚𝐝𝐞𝐫𝐬, 𝐚𝐧𝐝 𝐝𝐞𝐞𝐩 𝐥𝐞𝐚𝐫𝐧𝐢𝐧𝐠 𝐥𝐞𝐚𝐝𝐬. Firms are moving fast to secure talent that can bring resilience and innovation in an environment where every basis point matters. Our strength lies in being deeply connected to both clients and candidates—helping firms shape competitive offers while guiding talent toward platforms that have the leadership, infrastructure, and conviction to thrive through market cycles. 𝗧𝗵𝗶𝘀 𝗶𝘀 𝘁𝗵𝗲 𝗿𝗶𝗴𝗵𝘁 𝘁𝗶𝗺𝗲 𝘁𝗼 𝗵𝗮𝘃𝗲 𝘁𝗵𝗼𝘀𝗲 𝗰𝗼𝗻𝘃𝗲𝗿𝘀𝗮𝘁𝗶𝗼𝗻𝘀—𝘄𝗵𝗲𝘁𝗵𝗲𝗿 𝘆𝗼𝘂''𝗿𝗲 𝗹𝗼𝗼𝗸𝗶𝗻𝗴 𝘁𝗼 𝗯𝘂𝗶𝗹𝗱 𝘆𝗼𝘂𝗿 𝘁𝗲𝗮𝗺 𝗼𝗿 𝗲𝘅𝗽𝗹𝗼𝗿𝗲 𝘆𝗼𝘂𝗿 𝗻𝗲𝘅𝘁 𝘀𝘁𝗲𝗽. 𝗟𝗲𝘁''𝘀 𝗰𝗼𝗻𝗻𝗲𝗰𝘁. vick@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 17, 0, 2, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7354092466792194048/', '5-year anniversary flowers in hand and getting ready for a big team lunch 💐🍴 The office is buzzing today - lots of great energy, big placements, and plenty to celebrate. Keen to connect with experienced recruiters in our space who are curious about what else is out there. Very confident that our commission structure is the best there is - paired with a stellar platform, warm desks, and a genuinely collaborative, high-performing team. If you’re thinking about what your next move could look like, drop me a message or email shannon@durlstonpartners.com for a chat (even if speculative). …more', '9mo • Edited • 9 months ago • Edited • Visible to anyone on or off LinkedIn', 25, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7353897203393777668/', '🌍 𝐋𝐢𝐯𝐞 𝐑𝐨𝐥𝐞𝐬 𝐢𝐧 𝐭𝐡𝐞 𝐔𝐀𝐄 – 𝐉𝐮𝐥𝐲 𝐒𝐧𝐚𝐩𝐬𝐡𝐨𝐭🌍 We’re partnering with top quant funds expanding into the UAE. They’re hiring globally for high-impact roles. 💰 Pay: Top-tier comp, aligned with experience and contribution ✈️ Relocation: Full support incl. housing, schools & family services 🎯𝐀𝐈 𝐀𝐫𝐜𝐡𝐢𝐭𝐞𝐜𝐭 – 𝐈𝐧𝐯𝐞𝐬𝐭𝐦𝐞𝐧𝐭 𝐏𝐥𝐚𝐭𝐟𝐨𝐫𝐦 📍 UAE | First hire in AI team. Build tools to guide high-level portfolio decisions. 🔹 Needs: Proven AI/ML delivery, hands-on build, self-directed 🔧𝐉𝐮𝐧𝐢𝐨𝐫 𝐃𝐞𝐯𝐎𝐩𝐬 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 📍 UAE | Join platform team at global fund. Work across infra, scripting, support. 🔹 Needs: 2–4 YOE, Python/Bash, cloud basics, systems knowledge 🔧 𝐒𝐞𝐧𝐢𝐨𝐫 𝐃𝐞𝐯𝐎𝐩𝐬 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 📍 UAE | Infra-focused role in lean quant team. Own CI/CD, Kubernetes, IaC. 🔹 Needs: 6–15 YOE, Terraform, GitLab, observability, network/security 📊 𝐐𝐮𝐚𝐧𝐭 𝐏𝐌 – 𝐄𝐯𝐞𝐧𝐭/𝐌𝐋/𝐕𝐨𝐥 📍 UAE | New builds across vol, event-driven (macro, arb), and ML strategies. 🔹 Needs: Proven alpha, independent yet collaborative mindset 💻 𝐐𝐮𝐚𝐧𝐭 𝐃𝐞𝐯 – 𝐒𝐲𝐬𝐭𝐞𝐦𝐚𝐭𝐢𝐜 & 𝐀𝐧𝐚𝐥𝐲𝐭𝐢𝐜𝐬 📍 UAE | Cross-functional role in research, tooling, and infra. 🔹 Needs: Python + C++/Java, prototyping, experience in trading, AI, or pricing *We work closely with hiring managers and can offer fast feedback, transparent process insights, and full confidentiality.* If you''re open to a new challenge - or just curious what’s out there - feel free to DM me or email louis@durlstonpartners.com hashtag#UAE hashtag#Quant hashtag#Developer hashtag#Devops hashtag#AI hashtag#Portfoliomanager …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 16, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7353413184168292352/', 'Happy 5 year Durlston Partners birthday to me 🎉 Where has the time gone? Feels like I joined yesterday, but also like I’ve been here forever! From growing our London HQ to building teams in New York and Dubai… from Vegas to Ibiza, Paris to the Big Houses, and plenty of Dubai / NY trips packed between... it has been a lot of fun! But it’s the day-to-day moments and the people that make working here what it is. We’ve grown and matured together, learned loads, had a lot of laughs, and continue to build something really special. Big thanks to the DP crew for making the last 5 years fab! Here''s to the next 5 🥂 …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 62, 2, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7347978707103363073/', '🚨 We’re hiring for Dubai 🚨We’re looking for a curious, driven individual to join our growing Dubai team. We’re open on background - this could suit someone with a STEM or research-heavy degree who wants to move into a more commercial role and work with some of the smartest minds in the world. Or someone naturally sharp and ambitious, with a strong interest in finance and tech, who’s keen to build a career in a high-performing environment. Recruitment or sales experience is a plus, but not essential. You just need to be bright, switched-on, and up for a challenge. Must be open to relocating to Dubai (either immediately or with a start in our London office first). At Durlston Partners, we work with some of the most exciting names in the industry (hedge funds, HFTs, AMs, Prop Shops, FinTechs). Warm desks, brilliant clients, and a commission structure that in uncapped, plus BD incentives, profit share, and all the support you need to succeed. Interested? Drop me a message or email shannon@durlstonpartners.com We offer cash for successful referrals so if you know anyone who could be interested, send them my way. …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 34, 0, 3, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7347906298962698240/', 'Epic time at Silverstone with James Lacey (bday pressie from DP) - lots of driver spotting in the paddock (plus Keanu Reeves!!!) Classic British weather & an emergency jumper purchasing, but spirits were high & very happy to see Lando take P1 and Nico finally get a podium (eve though I''m team Mercedes and would''ve liked to see Lewis up there too!) Anyway… we’re hiring 👀 If you’re an experienced consultant looking to join a high-performing, collaborative team with warm desks (plenty of roles), global offices (London, New York, Dubai), and the most rewarding / generous commission, BD, and incentive structures in the market - we should chat. Drop me a message or email shannon@durlstonpartners.com …more', '9mo • Edited • 9 months ago • Edited • Visible to anyone on or off LinkedIn', 24, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7346812979016810497/', 'Happy Friday! ☀️Lots going on at Durlston Partners, and we’re making the most of these sunny summer days (with a few fun things to celebrate recently too 🎉💒). I''m having loads of great conversations with candidates in the market, and we’ve got a couple of seats to fill in our London office for the right people. We''re also looking for someone to start in London and relocate to Dubai to join team Rahnpreet Sandhu. If you’re an experienced consultant looking to join a high-performing, collaborative team (with offices in London, New York and Dubai) and want access to generous commission, BD incentives, profit share, and all the tools you need to succeed, we’re hiring. At Durlston Partners, we work with some of the most exciting names in the space. From day one, you’ll walk into warm desks, established client relationships, and the support to grow. Drop me a message or email shannon@durlstonpartners.com for a confidential chat. (Had to block out the logo on the client merch Warwick Poelman (واريك بولمان) was wearing!) …more', '9mo • Edited • 9 months ago • Edited • Visible to anyone on or off LinkedIn', 15, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7346175812758368257/', '🌟 Brilliant intern alert 🌟The amazing Orla Hunt (a current student at the University of Cambridge) is looking for a summer internship within an investment management or corporate legal team, and I wanted to share her details with my network in case anyone might be able to help. Orla has interned with us at Durlston Partners during university holidays over the past four years, and she is truly exceptional - smart, proactive, driven, and a joy to have in the office. She’s currently studying Human, Social and Political Sciences at Cambridge and was recently elected Head of Speakers at the Cambridge Union (where she’s hosted and interviewed high-profile guests like the CEO of Newsweek and the founder of Peachy Den). She’s been part of live pitches to board-level decision-makers in finance, completed multiple legal simulations with top firms, and has a growing network of professionals across both the legal and investment space. If you or someone in your network might be able to offer Orla a short-term internship this summer (or even just a useful conversation) please drop me a message and I’ll connect you. shannon@durlstonpartners.com hashtag#InternshipOpportunity hashtag#InvestmentManagement hashtag#CorporateLaw hashtag#CambridgeUniversity …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 46, 1, 5, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7345826328601849858/', '🩵', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 12, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7345472737441710082/', 'Back to work this afternoon post-Glastonbury - what an experience. Heart full! 💚 Even popped up on the BBC coverage a couple of times during Lewis Capaldi, clearly having the time of my life 😂 Now back at my desk and keen to speak to experienced recruiters who are exploring a new opportunity. At Durlston Partners, we partner with some of the most exciting names in the industry - you’ll walk into warm desks, strong client relationships, and a platform that gives you everything you need to build and grow. We offer market-leading commission with no thresholds or desk fees, a generous BD incentive, profit share, and the chance to be part of a high-performing team that genuinely supports each other. Our culture is collaborative, ambitious, and packed with great energy. If you’re curious, drop me a message or email shannon@durlstonpartners.com for a confidential chat. hashtag#TeamDP …more', '9mo • Edited • 9 months ago • Edited • Visible to anyone on or off LinkedIn', 35, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7343547314185158657/', 'Out of office 🎪 Heading to my first Glastonbury and am very excited! We’re hiring so if you’re an experienced consultant looking for a high-performing, collaborative team (with great clients, unbeatable commission and cash incentives, and a very special culture), feel free to drop me a message and we can set up a chat for when I’m back. At Durlston Partners, we partner with some of the most exciting names in the industry. From day one, you’ll have access to warm desks, strong client relationships, and all the tools and training you need to succeed. We offer: ✅ Market leading commission ✅ Generous BD incentives & meaningful profit share ✅ Equity opportunities ✅ International offices (London, NY, Dubai) ✅ Amazing socials, incentive trips, and a genuinely great team Right now, we’re looking for experienced consultants in London / Dubai who want to step into a mature platform and make an impact. 📧 shannon@durlstonpartners.com …more', '10mo • 10 months ago • Visible to anyone on or off LinkedIn', 20, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7342859766588686336/', 'Back from 3 Weeks in Dubai – Regional Market Pulse A quick update after spending the last few weeks on the ground in the UAE and speaking with clients across all regions. US: Senior mandates remain active. We’re in deep conversations with PMs and researchers across macro, volatility, and systematic equities. Seeing more crossover between stat arb and applied AI — especially on intraday alpha and signal infra. UAE: Big moves here. The GCC-wide Schengen-style tourist visa was just approved — a strong signal of regional coordination and growth. Add to that BlueCrest relocating key operations to the UAE, and you get a clear picture: this place is not just a hub, it’s the hub. And while the conflict a bit north has raised concerns across the broader region, the UAE has stayed neutral, resilient, and focused — continuing to position itself as a safe, forward-looking financial center. Markets are active, capital is flowing, and the momentum isn’t slowing. Asia: Hong Kong and Singapore are holding steady. An uptick in options trading mandates — delta-one, vol-focused, and everything in between. Firms are investing in execution upgrades and full-stack trading solutions. Also, live mandates across quant dev and mid-freq research. Europe: London and Paris remain busy. Demand is shifting toward multi-asset thinkers and systematic credit. Index rebalancing, ML overlays, and hybrid research+execution roles are coming up more frequently. …more', '10mo • 10 months ago • Visible to anyone on or off LinkedIn', 14, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7333505547830181889/', '💸 𝐑𝐞𝐟𝐞𝐫 𝐚 𝐅𝐫𝐢𝐞𝐧𝐝 💸 Know someone who might be a great fit for Durlston Partners? We offer cash for successful referrals, so if there’s someone in your network who should be part of a high-performing, fun, and genuinely rewarding team, send them my way. We’re hiring across London, Dubai, and New York, and are looking for experienced people from our space. Amazing clients, warm desks, exceptional commission with no desk fees or thresholds, BD incentives, profit share, top-tier perks… and we’re just back from our Vegas incentive trip. Message me or email shannon@durlstonpartners.com - referrals treated in confidence (and rewarded in cash). hashtag#ReferralsWelcome hashtag#Hiring hashtag#Recruitment hashtag#FinTech hashtag#HedgeFunds hashtag#WorkWithUs …more', '10mo • 10 months ago • Visible to anyone on or off LinkedIn', 11, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7333061755264253952/', 'Just back from our Vegas incentive trip - a really lovely mix of wholesome and typical Vegas... from exploring Red Rock Canyon, Lake Mead and the Hoover Dam… to a pool party with Mau P, David Guetta at LIV, and a surprise intimate Bruno Mars performance at his Pinky Ring lounge in the Bellagio. What made this trip even more special? It wasn’t just for top billers. While we do reward high performance, we also celebrate consistency, collaboration, and those who go above and beyond, like our peer-nominated “Team Player/Unsung Hero” and “DPer of the Year.” We’re big believers in recognising hard work all year round. That means regular team lunches in the best spots across London, NY and Dubai, Deliveroo days, socials, and much more. And most importantly: our commission structure is one of the best in the market (up to 40% with no thresholds or desk fees), we have a generous BD incentive, and profit share. We’re now looking to bring in experienced people from our space. If you''re curious about joining a high-performing team that actually rewards hard work (and has a lot of fun along the way), drop me a message for a confidential chat. 📧 shannon@durlstonpartners.com hashtag#Hiring hashtag#Vegas2025 hashtag#TeamCulture hashtag#FinTech hashtag#HedgeFunds hashtag#Recruitment …more', '11mo • 11 months ago • Visible to anyone on or off LinkedIn', 33, 0, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7330992391136440321/', 'I''ll be in Dubai and Abu Dhabi from June 2nd to 21st and would love to connect with Portfolio Managers open to a quick coffee or meeting while I''m in the region. We’re in touch with senior decision-makers across a number of funds in the UAE and can structure high-level, discreet introductions where there’s alignment. Whether you’re actively exploring or just open to understanding what’s out there, happy to share some honest market colour. Feel free to message me directly—always keen to build relationships ahead of when timing might make sense. …more', '11mo • 11 months ago • Visible to anyone on or off LinkedIn', 16, 0, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7329147378760876032/', 'Out of office 🚨Heading to New Orleans, then straight into our 2025 incentive trip to Vegas 🎲We’ve got some epic events lined up and I’m buzzing to get some of the team from all three offices - London, New York and Dubai - together in one place. At Durlston Partners, we work with the world’s top hedge funds, HFTs, AI firms, crypto firms and fintechs, helping them build high-performing teams with exceptional talent. I''m always keen to connect with experienced recruiters who want to be part of something genuinely high-performing and collaborative. If you’re thinking about your next move (or just want to hear more about what we’re building) drop me a message and we’ll line something up for when I’m back. 📩 shannon@durlstonpartners.com …more', '11mo • 11 months ago • Visible to anyone on or off LinkedIn', 15, 1, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7329080928293588992/', 'Update your address books - we’ve officially moved to Kendal House (so LinkedIn will be seeing the other corner of the building for a change 👀). We’re getting settled into the new London office and the good vibes are rolling - deals every day this week, offers flying, and the team firing on all cylinders. Feeling excited about what’s ahead and positive this momentum is only going to build. We’ve got two seats left in our London office for experienced recruiters - if you’re on the market or even just curious, we’d love to chat. Durlston Partners has been at the forefront of talent acquisition for the world’s top hedge funds, HFTs, AI/ML firms, digital asset firms, and fintechs since 2010. With offices in London, New York and Dubai, we build high-performing teams for multi-billion-dollar hedge funds, trading firms, and scaling startups. Our areas of expertise include: 🔹 Quant & Discretionary Trading 🔹 High-Frequency & Algo Trading 🔹 AI & Machine Learning 🔹 Crypto & Digital Assets 🔹 FinTech & Private Equity If you’re an experienced recruiter and want to be part of a high-performing team with a collaborative, grown-up culture, drop me a message or reach out at shannon@durlstonpartners.com. …more', '11mo • Edited • 11 months ago • Edited • Visible to anyone on or off LinkedIn', 16, 3, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7328771695777898496/', 'After four brilliant years at Maddox House, we’ve officially moved… about 20 steps away to our beautifully refurbed new office in Kendal House 🙌 (literally the opposite corner on Regent Street, higher ceilings, and, (apparently), better feng shui). End of an era - so many great memories in Maddox - Emily Lockyer did a great job on our final Friday pulling out some classic moments in Fri good news. Huge thanks to everyone we’ve shared the space with over the years - clients, candidates, teammates, friends - there’s been a lot of good times. Kendal House is a solid 10/10 and it has been great vibes already - lots of energy, deals flying, and no sign of things slowing down. More pics of the team in the new space soon. Really proud of what we continue to build here at Durlston Partners - and we’re always keen to speak to brilliant people in the market. If you’re a recruiter, client or candidate and want to chat, drop me a message or reach out at shannon@durlstonpartners.com …more', '11mo • Edited • 11 months ago • Edited • Visible to anyone on or off LinkedIn', 20, 2, 0, 'image', 0, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7328704795526008832/', '💭 𝑹𝒆𝒇𝒍𝒆𝒄𝒕𝒊𝒏𝒈 𝒐𝒏 𝑾𝒐𝒎𝒆𝒏 𝒂𝒕 𝒕𝒉𝒆 𝑻𝒂𝒃𝒍𝒆 - 𝑺𝒑𝒓𝒊𝒏𝒈 𝟐𝟎𝟐𝟓 💭 Last month, Durlston Partners hosted our annual Spring hashtag#WomenattheTable event, and I can''t stop thinking about it! This time it was held in our office, giving it a uniquely intimate, safe & warm feeling. This offered the opportunity to really speak in depth with the fabulous women in attendance, all at different stages of their careers and in different roles. Each brought their own perspective to topics such as career progression, AI & ML, data, quant finance, information security and, naturally, the barriers that women still face in the tech and finance industries. But we all agreed: we are stronger together, and it is events like this one that strengthen our community even further. We were also lucky to hear from Anh Clifton, who told us all about the latest in AI-driven quant finance; Hannah, who spoke passionately about the power of volunteering; Brooke M., who highlighted the importance of mentorship & adaptability; and Teagan Hill, who discussed her insights on emotional intelligence and performance. As always, it was an absolute pleasure to host this event, and I can''t wait for many more! hashtag#womenatthetable hashtag#womenintech hashtag#diversityandinclusion hashtag#londonevents …more', '11mo • 11 months ago • Visible to anyone on or off LinkedIn', 35, 2, 1, 'image', 1, NULL, 29934);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author, contact_id) VALUES ('durlston-partners', 'person', 'Shannon Palmer', 'https://www.linkedin.com/in/shannon-palmer-18a3219a/', 'https://www.linkedin.com/feed/update/urn:li:activity:7328684252747726851/', 'At Women at the Table, Brooke Lear shared how mentorship can help build confidence, resilience, and perspective, and how it''s not just something you benefit from later in your career. Even if you’re early on in your journey, you still have value to offer, whether that’s sharing your experience, listening with empathy, or just being a sounding board for someone else navigating a similar path. Mentorship is a two-way street, both mentor and mentee grow from the relationship. It encourages curiosity, accountability, and self-awareness. Brooke reminded us that mentoring doesn’t always have to be formal - sometimes just offering a conversation or support over coffee can make a real difference. https://lnkd.in/eb9-cSGB …more', '11mo • 11 months ago • Visible to anyone on or off LinkedIn', 10, 0, 2, 'image', 1, NULL, 29934);
